INSERT INTO public.photos VALUES (23006, 'Cine Coliseo a├▒os 90', 'Foto: ├üngel Lapresta. Pasaje de entrada al cine Coliseo Equitativa, ubicado en el paseo de la Independencia 19. Estuvo en funcionamiento desde 1949 hasta 1999. Fuente: www.facebook.com/photo.php?fbid=10207641816581574&set...', 1990, 1990, 1999, 'Anos 90', 'CENTRO', 41.65083600, -0.88196400, '0101000020E6100000A0FA07910C39ECBF9C8713984ED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/27759113721.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/27759113721.webp', 'https://www.flickr.com/photos/zaragozaantigua/27759113721/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23012, 'Miguel Indurain 1994', 'Foto: Guillermo Mestre. Fiestas del Pilar de 1994. Miguel Indurain (Villava, 1964), el ciclista espa├▒ol con mejor palmar├®s de la historia, participa en la segunda edici├│n del Crit├®rium Internacional Ciudad de Zaragoza. Gan├│ Perico Delgado. Al fondo, la calle del Marqu├®s de Casa Jim├®nez, en su emboque desde el paseo de la Independencia. Fuente: Heraldo de Arag├│n.', 1994, 1994, 1994, 'Anos 90', 'CENTRO', 41.64963100, -0.88358600, '0101000020E6100000B682A6255646ECBFE0BBCD1B27D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33116891760.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33116891760.webp', 'https://www.flickr.com/photos/zaragozaantigua/33116891760/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23061, 'Fernando Escart├¡n 1997', 'Imagen capturada durante la ceremonia de entrega de trofeos tras la celebraci├│n del Crit├®rium Fiestas del Pilar en su III Edici├│n. Recoge su reconocimiento como vencedor de la clasificaci├│n general el ciclista oscense Fernando Escart├¡n, que ya lo fue en la edici├│n de 1993, y lo ser├¡a en la de 1999. Esta prueba ciclista comenz├│ a disputarse en 1993, y ten├¡a como escenario el paseo de la Independencia. Hasta 2005 se celebraron diez de estas pruebas, que a├▒os m├ís tarde se retomaron en otra ubicaci├│n, otros patrocinadores y un car├ícter m├ís dom├®stico, sin el glamur de la etapa anterior. En la imagen, Fernando Escart├¡n recibe su premio con el preceptivo cachirulo y el fondo de la plaza de Santa Engracia.', 1997, 1997, 1997, 'Anos 90', 'CENTRO', 41.64949000, -0.88335800, '0101000020E6100000751E15FF7744ECBF1E8A027D22D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50498040707.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50498040707.webp', 'https://www.flickr.com/photos/zaragozaantigua/50498040707/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23063, 'P.┬║ de la Independencia 1997', 'Imagen capturada en el paseo/autopista de la Independencia durante la plantaci├│n de arbustos en la fina medianera entre los carriles de bajada a la plaza de Espa├▒a, con la intenci├│n de convertirlo en un mini corredor verde o estrecha cinta de vegetaci├│n en un oc├®ano de asfalto y veh├¡culos. Durante esta operaci├│n se inhabilit├│ al tr├ífico uno de los carriles, lo que aument├│ temporalmente el estr├®s circulatorio del centro urbano.', 1997, 1997, 1997, 'Anos 90', 'CENTRO', 41.65055700, -0.88257500, '0101000020E6100000E78C28ED0D3EECBF8997A77345D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50510349661.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50510349661.webp', 'https://www.flickr.com/photos/zaragozaantigua/50510349661/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23179, 'P.┬║ de la Independencia 2004', 'El 11 de marzo de 2004, una c├®lula yihadista provoc├│ varias explosiones en trenes de cercan├¡as de Madrid, falleciendo 193 personas y resultando heridas alrededor de 2.000. Al d├¡a siguiente se convocaron manifestaciones de repulsa, mientras la versi├│n oficial aseguraba la autor├¡a de ETA. En Zaragoza se anunci├│ la comparecencia de medio mill├│n de personas. En la imagen, la manifestaci├│n, a su paso por el paseo de la Independencia, vista desde la plaza de Espa├▒a. Fuente: Heraldo de Arag├│n.', 2004, 2004, 2004, 'Siglo XXI', 'CENTRO', 41.65019900, -0.88332600, '0101000020E61000009D9B36E33444ECBF2A7288B839D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/38335017061.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/38335017061.webp', 'https://www.flickr.com/photos/zaragozaantigua/38335017061/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23238, 'Arrabal de Sinhaya 2002', 'Durante las obras para construir un aparcamiento subterr├íneo que se descart├│ en el paseo de la Independencia de Zaragoza, aparecieron los restos de la barriada musulmana de los Sinhaya, tribus bereberes del norte de ├üfrica. Tambi├®n se encontraron trazas de una iglesia rom├ínica, quiz├ís la primera construcci├│n cristiana de la ciudad. En el Arrabal de Sinhaya se alzaba la mezquita de Abu Jalid, e inclu├¡a las actuales plaza de Salamero y calle del Azoque. El conjunto es de los siglos XI y XII, justo antes de que Alfonso I conquistara Medina Albaida Saraqusta, y con ella su barrio artesano, convertido en morer├¡a. Fuente visual: ABC.', 2002, 2002, 2002, 'Siglo XXI', 'CENTRO', 41.65082100, -0.88225300, '0101000020E61000004C88B9A46A3BECBF67463F1A4ED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14904366960.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14904366960.webp', 'https://www.flickr.com/photos/zaragozaantigua/14904366960/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23641, 'Calle Casa Jim├®nez 1925', 'AHPZ. Archivo fotogr├ífico Julio Requejo. 11/06/1925. "Gigantes y cabezudos." Desde la altura de uno de los edificios de viviendas de la ├®poca, imagen de la calle Marqu├®s de Casa Jim├®nez en el momento en que pasa por ella la comparsa de Gigantes y Cabezudos. La verja de la izquierda pertenece al recinto del Gobierno Militar, instalado sobre el Convento de las Descalzas de San Jos├®, all├¡ situado desde el siglo XVI (con restos de la iglesia, el claustro, y las bodegas) que, tras las recientes alineaciones hab├¡a quedado localizado en una manzana delimitada por las calles de Albareda, Ponzano (a la izquierda) y la de Bilbao (al fondo, donde comienza el extenso Cuartel de Artiller├¡a del Carmen). La calle de Casa Jim├®nez llegaba, haciendo curva hacia la derecha, hasta la denominada "Plaza del Pueblo" y la calle del Azoque.', 1925, 1925, 1925, 'Anos 20', 'CENTRO', 41.64996300, -0.88445300, '0101000020E6100000BB2BBB60704DECBF164ED2FC31D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15402341555.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15402341555.webp', 'https://www.flickr.com/photos/zaragozaantigua/15402341555/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23960, 'El Petit Park 1917', 'AHPZ. Archivo Julio Requejo. 14/10/1917. "Fiesta de Jota en el Petit-Park." El "Teatro del Petit Park", aunaba el concepto de parque de atracciones, con teatro al aire libre, y m├║sica en directo. El lugar eran los antiguos terrenos de la Exposici├│n Hispano-Francesa de 1908, a├║n sin urbanizar, al lado de la nueva Plaza de Castelar. En la imagen, uno de los festivales de jota que se celebraban en la ciudad. Al fondo, el Teatro Circo y la chimenea de la central el├®ctrica de ERZ en la calle Isaac Peral esquina con San Miguel. Cuando se completara la urbanizaci├│n de la zona, este ef├¡mero Teatro echar├í el tel├│n.', 1917, 1917, 1917, 'Anos 10', 'CENTRO', 41.64986700, -0.88067600, '0101000020E610000036E84B6F7F2EECBFF4DF83D72ED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14925205087.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14925205087.webp', 'https://www.flickr.com/photos/zaragozaantigua/14925205087/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23963, 'De entre los muertos 1959', 'Eficaz anuncio ambulante de la pel├¡cula V├®rtigo (1958) de Alfred Hitchcock. Coche f├║nebre aparcado en el paseo de la Independencia, frente al Cine Alhambra, donde se proyecta desde hace ya 11 semanas, seg├║n reza el cartel de la izquierda. Fuente: Colecci├│n GOG.', 1959, 1959, 1959, 'Anos 50', 'CENTRO', 41.65050700, -0.88256600, '0101000020E61000001AF8510DFB3DECBFD76839D043D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14940504556.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14940504556.webp', 'https://www.flickr.com/photos/zaragozaantigua/14940504556/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23964, 'Teatro Circo 1960', 'Ayuntamiento de Zaragoza/Gerardo Sancho, 1960. El Teatro Circo estaba situado en la esquina de la calle San Miguel con Isaac Peral, donde hoy hay un estanco. Estuvo en pie de 1887 hasta 1961.', 1960, 1960, 1960, 'Anos 60', 'CENTRO', 41.65079100, -0.88036900, '0101000020E6100000F030ED9BFB2BECBFFCC3961E4DD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14982614255.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14982614255.webp', 'https://www.flickr.com/photos/zaragozaantigua/14982614255/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23997, 'Paseo Independencia 1959', 'Aspecto parcial de la comparsa publicitaria del Circo Espa├▒ol, en las fiestas del Pilar de 1959. Al fondo, la tienda de fotograf├¡a de Miguel Mar├¡n Chivite, en el entonces n├║mero 12 del paseo de la Independencia. Fuente: www.todocoleccion.net', 1959, 1959, 1959, 'Anos 50', 'CENTRO', 41.65089300, -0.88241400, '0101000020E61000009A0AF148BC3CECBF01193A7650D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21026706684.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21026706684.webp', 'https://www.flickr.com/photos/zaragozaantigua/21026706684/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24016, 'Paseo Independencia 2001', 'El Colectivo Pedalea nace en la Universidad de Zaragoza en septiembre de 1990, recogiendo iniciativas anteriores de reivindicaci├│n de la bicicleta como transporte urbano, como las de la Asamblea Ecologista. Desde 2001 organiza una Marcha Ciclonudista anual, para visibilizar este modelo de desplazamiento y solicitar mayor atenci├│n por parte de la Administraci├│n. En 2015, el Ayuntamiento de Zaragoza concedi├│ el t├¡tulo de Hijo Predilecto a esta asociaci├│n. En la foto, primera Marcha Ciclonudista, el 14 de junio de 2001 en el paseo de la Independencia. Tras los ciclistas, la acera de los impares. Fuente: Agencia EFE.', 2001, 2001, 2001, 'Siglo XXI', 'CENTRO', 41.65028300, -0.88272600, '0101000020E61000005186AA984A3FECBF88122D793CD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24356130090.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24356130090.webp', 'https://www.flickr.com/photos/zaragozaantigua/24356130090/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24037, 'P.┬║ de la Independencia 1931', 'Domingo, 29 de marzo de 1931, paseo de la Independencia. Manifestaci├│n pro amnist├¡a organizada por el Partido Republicano Radical Socialista, previamente autorizada por el gobernador civil. Fuente visual: www.facebook.com/photo.php?fbid=10208274413570623&set...', 1931, 1931, 1931, 'Anos 30', 'CENTRO', 41.64978900, -0.88356600, '0101000020E6100000EF703B342C46ECBF782634492CD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30139127726.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30139127726.webp', 'https://www.flickr.com/photos/zaragozaantigua/30139127726/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24068, 'Teatro Circo 1960', 'Imagen interior del peculiar Teatro Circo, construido en 1887 sobre unos antiguos lavaderos esquineros entre la calle de los Sitios, y la de San Miguel, teniendo por trasera la enorme huerta del convento de Jerusal├®n. A lo largo de su vida al servicio del espect├ículo, fue objeto de numerosas reformas y modificaciones, hasta resultar en esta imagen, en sus ├║ltimos tiempos de funcionalidad. Estuvo activo hasta 1961, y fue derribado al a├▒o siguiente. Fuente visual: foto Gerardo Sancho Ramo, en AMZ.', 1960, 1960, 1960, 'Anos 60', 'CENTRO', 41.65079900, -0.88038500, '0101000020E61000005C72DC291D2CECBF7FA2B2614DD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33902070272.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33902070272.webp', 'https://www.flickr.com/photos/zaragozaantigua/33902070272/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24083, 'Fiesta de la Flor 1916', 'Foto: S├ínchez Rom├ín. Puesto de recaudaci├│n durante la Fiesta de la Flor, instalado en la plaza de Santa Engracia. Detr├ís, valla perimetral del Teatro Pignatelli. Fuente: Revista Blanco y Negro, 21-5-1916.', 1916, 1916, 1916, 'Anos 10', 'CENTRO', 41.64941500, -0.88343300, '0101000020E61000001FA166481545ECBF1344DD0720D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/42703308505.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/42703308505.webp', 'https://www.flickr.com/photos/zaragozaantigua/42703308505/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24108, 'Calle de San Miguel 1937', 'Imagen capturada en el Teatro Circo durante el transcurso del festival del Auxilio de Invierno organizado el 17 de marzo de 1937 por Falange. En el engalanado escenario, decorado con los retratos del "General├¡simo" Franco y de Jos├® Antonio Primo de Rivera (en la imagen), adem├ís de con las banderas de Falange y de la Espa├▒a nacionalista, figura junto a un piano el gran tenor Miguel Fleta ataviado con el uniforme de falangista, durante su actuaci├│n programada, que culmin├│ cantando con el brazo en alto el Himno de Falange, tras el que profiri├│ los "gritos reglamentarios" ("Arriba Espa├▒a", y etc.) contestados un├ínimemente por el enfervorizado p├║blico asistente.', 1937, 1937, 1937, 'Anos 30', 'CENTRO', 41.65077300, -0.88045100, '0101000020E610000039605793A72CECBF560F98874CD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51817689172.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51817689172.webp', 'https://www.flickr.com/photos/zaragozaantigua/51817689172/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24111, 'Paseo de la Independencia 1918', 'Ceremonia de la jura de bandera de los reclutas del servicio militar obligatorio de tres a├▒os, el 2 de marzo de 1918 en el paseo de la Independencia. Al fondo, el quiosco de la m├║sica y la plaza de la Constituci├│n.', 1918, 1918, 1918, 'Anos 10', 'CENTRO', 41.65042000, -0.88277900, '0101000020E6100000060FD3BEB93FECBF08556AF640D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/52021750525.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/52021750525.webp', 'https://www.flickr.com/photos/zaragozaantigua/52021750525/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24116, 'P.┬║ de la Independencia 1917', 'Imagen capturada desde la altura del Monumento al Justiciazgo en la plaza de Arag├│n con una vista del abarrotado paseo de la Independencia durante el paso de la funeraria comitiva del torero Florentino Ballesteros en su trayecto desde el Hospicio Provincial por algunos c├®ntricos viales el d├¡a 26 de abril de 1917. Hacia el fondo, el Quiosco de la M├║sica en su temporal emplazamiento en el bulevar del paseo. El f├®retro, en la parte superior de la escena, aparece conducido a hombros por los toreros de la ciudad, que en la plaza de la Constituci├│n tomaron el relevo a los asilados del Hospicio. Tras ellos, el alcalde, Gumersindo Claramunt Pastor, el presidente de la Diputaci├│n provincial, Enrique Isabal Pallar├®s, una numerosa Comisi├│n de diputados en Cortes y varios jefes y oficiales militares, concejales, periodistas. La banda de m├║sica del Hospicio interpret├│ durante el recorrido algunas marchas f├║nebres. Tras el p├║blico en general, un buen n├║mero de coches, algunos de los cuales transportaban las coronas de flores. Poco despu├®s y a la altura de la Facultad de Medicina y Ciencias, el canto de un responso marc├│ el final de trayecto del cortejo y duelo p├║blico. El f├®retro fue depositado en un carruaje que lo condujo inmediatamente al cementerio cat├│lico de Torrero, donde fue inhumado.', 1917, 1917, 1917, 'Anos 10', 'CENTRO', 41.65042000, -0.88277900, '0101000020E6100000060FD3BEB93FECBF08556AF640D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/52248960354.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/52248960354.webp', 'https://www.flickr.com/photos/zaragozaantigua/52248960354/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24128, 'P.┬║ de la Indepedencia 1916', 'Fotograma de un reportaje dedicado a la ceremonia de "jura de banderas" de los reclutas de la guarnici├│n celebrada el d├¡a 5 de marzo de ese a├▒o en el paseo de la Independencia. En un d├¡a de cierzo furioso, el acto se inici├│ con una ceremonia religiosa oficiada en el Quiosco de la M├║sica y finaliz├│ con desfiles militares en el paseo de Pamplona. Esa jornada hubo rancho "extraordinario" para la tropa y permiso para asistir luego a los "espect├ículos p├║blicos". En la imagen, ├│sculo de un recluta al estandarte de su Cuerpo. En la prensa de la ├®poca, al hilo de este evento, se afirmaba que "Si vosotros (los nuevos reclutas) deposit├íis vuestra fe y vuestra confianza en las virtudes de quienes os mandan, no lo dud├®is, encontrar├®is abierto y f├ícil el camino de la gloria". Esa misma gloria la estaban alcanzando, en ese mismo momento, las tropas francesas y alemanas enfrentadas por el control de las colinas fortificadas de Verd├║n en el marco de la Gran Guerra. Habr├¡a gloria para dar y tomar: se estima que esta batalla ocasion├│ un mill├│n de bajas entre ambos bandos en los diez meses que dur├│. Esa misma gloria fue rodada por Stanley Kubrick en el filme "Paths of glory" (1957), ambientada en el frente franc├®s durante el a├▒o 1916. Tal vez por hacerlo tan certeramente esta pel├¡cula no pudo ser estrenada en Zaragoza hasta 1986.', 1916, 1916, 1916, 'Anos 10', 'CENTRO', 41.65058900, -0.88251100, '0101000020E610000038876BB5873DECBF9411178046D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/54734766556.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/54734766556.webp', 'https://www.flickr.com/photos/zaragozaantigua/54734766556/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24134, 'Petit Park c.1917', 'Imagen del "Teatro del Petit Park" en una zona de las antiguas instalaciones de la Exposici├│n Hispano-Francesa de 1908, en lo que fuera huerta de Santa Engracia, entonces plaza de Castelar. Tras el desmantelamiento de la mayor parte de los ef├¡meros componentes de la Expo, y hasta que la urbanizaci├│n de la zona vaya progresando, este Teatro ser├í un curioso espacio de entretenimiento, con espect├ículos variados. En esta imagen, una irrepetible visual de la ciudad. De izquierda a derecha, las huertas del convento de Jerusal├®n y la enorme chimenea de la central de la "Electra Peral Zaragozana", en la esquina de la calle San Miguel con la de los Sitios. A su derecha, las traseras del "Teatro Circo". Al fondo, el remate de la torre de la Seo. A continuaci├│n, las traseras de los actuales n├║meros 14, 16 y 18 de viviendas de la calle San Miguel, levantados en la d├®cada de los ochenta del siglo XIX. Por encima de ellos sobresale la chimenea de la otra central electrica que hab├¡a entre las calles de Blancas y Porcell. En el centro, el convento de Santa Catalina. A la derecha, la torre de la iglesia de San Miguel. Esta descripci├│n ha tenido su utilidad en la comunicaci├│n "Instant├íneas de un ┬½Para├¡so de recreo┬╗ en Zaragoza: el desaparecido Petit Park ÔÇôluego Saturno ParkÔÇô (1920-1925)", firmada por M├│nica V├ízquez Astorga y Rebeca Carretero Calvo, incluida en "II Jornadas sobre Investigaci├│n en Historia de la Fotograf├¡a. 1839-1939: Un siglo de fotograf├¡a", Hern├índez Latas, Jos├® Antonio (ed.), IFC, 2018. Fuente visual: panor├ímica posiblemente realizada sobre la base de tres postales editadas por Lucas Escol├í en la serie titulada "PETIT-PARC PRO-INFANCIA. ZARAGOZA", Colecci├│n Gerardo Alca├▒iz, en "El libro de oro de Arag├│n", EPA, 1997.', 1917, 1917, 1917, 'Anos 10', 'CENTRO', 41.64986700, -0.88067600, '0101000020E610000036E84B6F7F2EECBFF4DF83D72ED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19198805050.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19198805050.webp', 'https://www.flickr.com/photos/zaragozaantigua/19198805050/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24280, 'Puerta de Santa Engracia 1737', '"Primera Puerta de Santa Engracia", Antonio Callaved, 2010. Construida junto al monasterio de Santa Engracia, fue derruida en los sitios. Fuente: pinturascallaved.wordpress.com/5-mi-pintura-en-la-filatelia/', 1737, 1737, 1737, 'Siglo XIX', 'CENTRO', 41.64940100, -0.88334700, '0101000020E61000007BA180ED6044ECBFAE7E6C921FD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15093271329.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15093271329.webp', 'https://www.flickr.com/photos/zaragozaantigua/15093271329/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24295, 'Calle Sanclemente 1980', 'La especulaci├│n inmobiliaria en Zaragoza no es una plaga b├¡blica, ni una pena tristosa cuyo objetivo es afear la belleza natural de la preciosa ciudad en que vivimos. "Sigue al dinero" aconsejan en las pelis que tratan de la corrupci├│n y la especulaci├│n, y no les falta raz├│n: junto a la "liberaci├│n" de enormes cantidades de suelo urbano en el precioso centro de la ciudad, la especulaci├│n inmobiliaria en Zaragoza lleva asociado el piqueteo de industrias ("Carde y Escoriaza", "Mercier", "Lanera Aragonesa", "Textil Pina", "Alumalsa"...), conventos (las Fecetas, Santa In├®s, Santa Luc├¡a, las Adoratrices, Altab├ís...), colegios confesionales (Sagrado Coraz├│n, El Salvador, Carmelitas, Santa Ana, La Salle Montemol├¡n, Teresianas...), de forma que el aroma monetario, la "grasa" que engrasa los mecanismos de este proceso, nos conduce a las grandes fortunas asociadas al aut├®ntico "monopoly" que se juega en la ciudad. La triste p├®rdida de edificios de factura que merecer├¡a su preservaci├│n, s├│lo es la epidermis, la fachada, de un asunto que hunde sus ra├¡ces en la trama de poder y las redes pol├¡ticas y econ├│micas que manejan el cotarro zaragozano, en un escenario no muy sustancialmente diferente antes y despu├®s de la autoproclamada "transici├│n". En la imagen, chafl├ín de las calles Sanclemente-Isaac Peral donde una apuntada puerta en formas neog├│ticas (aqu├¡ eclipsada por un cartel├│n publicitario) se├▒alaba el acceso al antiguo Colegio Teresiano N┬¬ S┬¬ del Pilar, de la Compa├▒├¡a de Santa Teresa de Jes├║s, ideado por Teodoro R├¡os Balaguer y activo en esta ubicaci├│n desde 1926. Este colegio ocupaba un buen bocado, en lo m├ís granado del "centro". La desventurada historia del solar es prolija: pas├│ por varias manos como las tarjetas de propiedad del "monopoly". El momento de la captura de la imagen ilustra un espacio de tiempo de los denominados "barbecho expectante", a la espera de un reajuste de ofertas. Finalmente, el edificio fue piqueteado, y sobre ├®l se levant├│ el cementoso y compacto ', 1980, 1980, 1980, 'Anos 80', 'CENTRO', 41.64970700, -0.88103000, '0101000020E6100000A86F99D36531ECBFBB7D569929D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/16315237291.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/16315237291.webp', 'https://www.flickr.com/photos/zaragozaantigua/16315237291/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24301, 'Pl. de Santa Engracia 1927', 'Dibujo de Ambrosio Ruste que representa la zona de escaleras de acceso de la plaza de Santa Engracia al paseo de la Independencia de Zaragoza, la casa Pamplona Escudero (a la derecha), luego derribada. Al fondo, el edificio del n├║mero 30 del paseo de la Independencia. Fuente: ┬íAqu├¡... Zaragoza!, Jos├® Blasco Ijazo, 1952.', 1927, 1927, 1927, 'Anos 20', 'CENTRO', 41.64955400, -0.88348000, '0101000020E61000004C7155D97745ECBF357EE19524D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19212269103.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19212269103.webp', 'https://www.flickr.com/photos/zaragozaantigua/19212269103/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24306, 'Victoria Eugenia 1908', 'Foto: Ignacio Coyne, 1908. "Inauguraci├│n de la Exposici├│n Hispano Francesa". En el centro, la reina Victoria Eugenia. Tras ella, el rey Alfonso XIII. Detr├ís, la iglesia de Santa Engracia, el Pabell├│n de Francia y el Quiosco de la M├║sica. La inauguraci├│n de la Exposici├│n Hispano Francesa de Zaragoza ya hab├¡a tenido lugar. Los reyes inauguraron el Monumento a los Sitios. Fuente: dara.aragon.es/', 1908, 1908, 1908, 'Anos 1900', 'CENTRO', 41.64967500, -0.88057900, '0101000020E6100000986BD102B42DECBFB003E78C28D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19606723055.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19606723055.webp', 'https://www.flickr.com/photos/zaragozaantigua/19606723055/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24307, 'Ilusiorama 1908', 'En la zona pr├│xima al Pabell├│n Franc├®s de la Exposici├│n Hispano Francesa de Zaragoza, se hallaba la zona denominada Parque de Atracciones, que sobrevivir├í a la muestra con el nombre de Petit Park. Inclu├¡a tiro al blanco, barcas voladoras, el hilo de amor, cinemat├│grafo, tobog├ín e ilusiorama. Este ├║ltimo contaba con patio de butacas y proyecci├│n de cine multiplicada por espejos, que rodeaban al espectador, simult├íneamente a la actuaci├│n de bailarinas del Teatro Real de Madrid con m├║sica en directo y efectos luminosos mediante 2000 l├ímparas. Fuente visual: "Secci├│n de Espect├ículos. Ilusiorama", foto Ignacio Coyn├®, en "├ülbum oficial descriptivo Exposici├│n Hispano-Francesa 1908.', 1908, 1908, 1908, 'Anos 1900', 'CENTRO', 41.64986700, -0.88067600, '0101000020E610000036E84B6F7F2EECBFF4DF83D72ED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19615613015.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19615613015.webp', 'https://www.flickr.com/photos/zaragozaantigua/19615613015/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24314, 'Calle Zurita 1976', 'En la imagen, chafl├ín de la entrada principal al Colegio Teresiano del Pilar desde la calle Zurita 12. Destaca el recrecimiento vertical a├▒adido a la traza original que Teodoro R├¡os Balaguer dise├▒├│ en 1925 La calle Isaac Peral cruza Zurita y, al fondo a la izquierda, la Escuelas de Artes Aplicadas y Oficios Art├¡sticos, en la plaza de Jos├® Antonio. Fuente: aportaci├│n de Elena de Salas, Directora General, y Presidenta del Consejo Escolar, del Colegio Teresiano del Pilar.', 1976, 1976, 1976, 'Anos 70', 'CENTRO', 41.65008600, -0.88093200, '0101000020E6100000F4FE3F4E9830ECBF32CB9E0436D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22858749517.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22858749517.webp', 'https://www.flickr.com/photos/zaragozaantigua/22858749517/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24315, 'Calle Sanclemente 1976', 'Como los pisos del 19 de la calle del Pilar se les hab├¡an quedado chicos, al principio de los a├▒os 20 las HH. Teresianas comenzaron a buscar una nueva ubicaci├│n, m├ís espaciosa, para su colegio, que encontraron en los promisorios terrenos en urbanizaci├│n de la antigua huerta de Santa Engracia, en el entorno de la nueva plaza de Castelar. Teodoro R├¡os Balaguer firm├│ el dise├▒o, en 1925, de la nueva planta del centro (una curiosa combinaci├│n de aportes neog├│ticos, mud├®jares, y racionalistas) con provisional direcci├│n en "calle de los Sitios s/n", aunque la prolongaci├│n del vial Sanclemente les adjudic├│ ese nomencl├ítor, con el n├║mero 15. El curso 1926-27 fue el primero en este emplazamiento del nuevo colegio, que en 1958 fue ampliado en horizontal hasta la calle Zurita, donde se situ├│ la nueva entrada principal, con el n├║mero 12. En 1960 fue ampliado, esta vez en vertical, para adecuarlo a su nueva funcionalidad como Colegio, Residencia Universitaria, y sede de Comunidad Religiosa. En total, unas 500 personas entre residentes temporales y permanentes. A mediados de los a├▒os 70, la nueva Ley General de Educaci├│n segu├¡a sin ser aplicada en lo relativo a las caracter├¡sticas requeridas a los centros educativos homologados (mayor superficie ├║til por alumno, instalaciones deportivas, servicios de biblioteca, laboratorio, sala de usos m├║ltiples, sala de profesores...). Este centro no pod├¡a adaptarse a esos demandas espaciales, (de donde no hay, no se puede sacar), de forma que en 1978 se traslad├│ a la ultraperiferia de la ciudad (camino de Pinseque, n┬║ 37), donde hoy sigue. Un par de a├▒os antes, en 1976, se hab├¡a celebrado el Centenario I de la fundaci├│n de la Compa├▒├¡a de Santa Teresa de Jes├║s, por Enrique de Oss├│ y Cervell├│. El edificio abandonado entr├│ en la habitual espiral especulativa propia de aquellos a├▒os. Y de los siguientes. En la imagen, chafl├ín de entrada al Colegio Teresiano del Pilar desde la calle de Felipe Sanclemente. A la izquierda, la de Isaac Peral, y al fon', 1976, 1976, 1976, 'Anos 70', 'CENTRO', 41.64970700, -0.88103000, '0101000020E6100000A86F99D36531ECBFBB7D569929D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23110592862.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23110592862.webp', 'https://www.flickr.com/photos/zaragozaantigua/23110592862/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24319, 'Exposici├│n de 1908', 'Imagen capturada en el interior del recinto de la Exposici├│n Hispano-Francesa de 1908 y centrada en el Quiosco para m├║sica dise├▒ado por los hermanos Jos├® y Manuel Mart├¡nez de Ubago y Liz├írraga, y el espacio habilitado alrededor para p├║blico asistente. Tras el quiosco, instalaci├│n de jardiner├¡a y arboricultura francesas y fachada principal del Pabell├│n franc├®s o de los franceses, proyectado por Joseph-Charles de Guirard de Montarnal y encargado de su construcci├│n F├®lix Navarro P├®rez. A la derecha, vista parcial del Parque de atracciones habilitado en la muestra. Al fondo, edificios de las calles de Zurita y Huertas. Fuente visual: Archivo fotogr├ífico hist├│rico del SIPA, en AHPZ.', 1908, 1908, 1908, 'Anos 1900', 'CENTRO', 41.64942800, -0.88042800, '0101000020E61000002E724F57772CECBFA88DEA7420D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31240611188.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31240611188.webp', 'https://www.flickr.com/photos/zaragozaantigua/31240611188/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24323, 'Minas 1809', '"Plano parcial de Zaragoza usado por los franceses, y en el que se ven se├▒alados los lugares donde se colocaron los hornillos de p├│lvora". Fotograf├¡a de 1950. Guerra de minas en el segundo sitio de Zaragoza (1809). Abarca desde el Coso (al norte) hasta la huerta de Santa Engracia. Fuente: Museo del Ej├®rcito.', 1809, 1809, 1809, 'Siglo XIX', 'CENTRO', 41.64940700, -0.88201900, '0101000020E6100000836BEEE87F39ECBF9065C1C41FD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31913436763.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31913436763.webp', 'https://www.flickr.com/photos/zaragozaantigua/31913436763/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24371, 'Gran Hotel 1966', 'Imagen del Gran Hotel, chafl├ín calle Costa-Isaac Peral, con aspecto parcial, al fondo a la izquierda, del Colegio Teresiano N┬¬ S┬¬ del Pilar, de la Compa├▒├¡a de Santa Teresa de Jes├║s, en esa ubicaci├│n desde 1926. Fuente visual: Gerardo Sancho Ramo, AMZ.', 1966, 1966, 1966, 'Anos 60', 'CENTRO', 41.64970700, -0.88103000, '0101000020E6100000A86F99D36531ECBFBB7D569929D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15597066558.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15597066558.webp', 'https://www.flickr.com/photos/zaragozaantigua/15597066558/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24421, 'Calle de C├ídiz c.1925', 'Imagen capturada en altura desde las traseras de la calle Casa Jim├®nez, y centrada en la huerta del colegio de las Reverendas Hermanas Carmelitas de la Tercera Orden o Terciarias sito en la calle de C├ídiz n┬║ 2, heredero de la que fuera antigua Casa de las Recogidas, y editada como parte de una colecci├│n de postales publicitarias realizadas por el estudio de fotograf├¡a Machetti, sito en el piso principal del n┬║ 27 del Coso Alto. Al comienzo de la d├®cada de los 70 del pasado siglo XX este colegio estaba gestionado por Carmelitas Misioneras Teresianas que en 1977 lo vendieron para costearse unas nuevas y lejanas instalaciones en el barrio de Casablanca. El antiguo edificio colegial, incluyendo la neocl├ísica iglesia de su interior, fue derribado al poco tiempo para levantar sobre su solar una pionera y moderna gran superficie comercial. Al fondo, y emergentes sobre el entorno de la calle del Laurel, las dos primeras torres del Templo Metropolitano del Pilar. Fuente visual: www.todocoleccion.net/', 1925, 1925, 1925, 'Anos 20', 'CENTRO', 41.65071900, -0.88402200, '0101000020E610000071395E81E849ECBF63F19BC24AD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/35632572195.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/35632572195.webp', 'https://www.flickr.com/photos/zaragozaantigua/35632572195/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25065, 'Miguel Fleta 1925', '"Zaragoza, 7 de junio de 1925. Festival a beneficio de la Asociaci├│n de la Prensa en el Teatro Circo de Zaragoza. En el centro: Miguel Fleta. A su derecha: Alejandro Castej├│n Gay, Jefe de Tramoya del citado Teatro Circo. Primero por la izquierda, con traje claro, chalina y luto en la solapa (al estilo de la ├®poca): Mariano Gimeno, sobrino del famoso Eduardo Gimeno, autor de la pel├¡cula Salida de Misa de 12 del Pilar de Zaragoza." Fuente: rafaelcastillejo.com', 1925, 1925, 1925, 'Anos 20', 'CENTRO', 41.65086800, -0.88044100, '0101000020E610000056D7A19A922CECBFA80183A44FD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15004235812.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15004235812.webp', 'https://www.flickr.com/photos/zaragozaantigua/15004235812/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25137, 'Edificio Ambos Mundos 1945', 'Dibujo publicitario del edificio levantado en el n├║mero 30 del paseo de la Independencia de Zaragoza (hoy 32 y 34). Albergaba el caf├® Ambos Mundos en sus bajos desde 1881, cuando fue comprado por el Banco de Cr├®dito de Zaragoza, fundado en 1845. En 1947, esta entidad fue absorbida por el Banco Central. El 2 de septiembre de 1955, cerr├│ el caf├®. Hoy, esta casa est├í despojada de su ornamentaci├│n exterior. Fuente: Revista Arag├│n, 1945.', 1945, 1945, 1945, 'Anos 40', 'CENTRO', 41.64932200, -0.88425900, '0101000020E61000007F32C687D94BECBF6249B9FB1CD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20760836905.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20760836905.webp', 'https://www.flickr.com/photos/zaragozaantigua/20760836905/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25269, 'Cine Coliseo Equitativa c.1956', 'Foto Gonzalo Bull├│n. Construido en 1949, con proyecto de Jos├® de Yarza y Manuel Mart├¡nez, la imagen captura el aspecto de su pantalla tras haber sido adaptada en 1955 para la proyecci├│n en sistema "cinemascope". Reconvertido en gran superficie comercial de ropa, conserva a la vista la techumbre de madera.', 1956, 1956, 1956, 'Anos 50', 'CENTRO', 41.65060800, -0.88173800, '0101000020E61000008D7E349C3237ECBF0B42791F47D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14823138138.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14823138138.webp', 'https://www.flickr.com/photos/zaragozaantigua/14823138138/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25272, 'P.┬║ de la Independencia 1930', '"Paseo de la Independencia". Sol de invierno, en el tramo entre Casa Jim├®nez, a la izquierda, y la Plaza de la Constituci├│n, al fondo. Los ├írboles del boulevard, plantados hac├¡a poco.', 1930, 1930, 1930, 'Anos 30', 'CENTRO', 41.64949000, -0.88369100, '0101000020E61000000AA018593247ECBF1E8A027D22D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14955532288.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14955532288.webp', 'https://www.flickr.com/photos/zaragozaantigua/14955532288/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25274, '8 de marzo de 1936', 'Jornada Internacional de la Mujer del 8 de marzo de 1936 en Zaragoza. Una de las manifestaciones m├ís multitudinarias convocadas en la ciudad por las fuerzas de izquierda durante la Segunda Rep├║blica espa├▒ola, con m├ís de 20.000 participantes. En la imagen, mujeres y hombres participantes en la manifestaci├│n en el Paseo de la Independencia.', 1936, 1936, 1936, 'Anos 30', 'CENTRO', 41.64935400, -0.88384100, '0101000020E61000005DA5BBEB6C48ECBF6EC328081ED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14980402266.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14980402266.webp', 'https://www.flickr.com/photos/zaragozaantigua/14980402266/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25276, '8 de marzo de 1936', 'AHPZ. Archivo Fotogr├ífico Coyne. Manuel Coyne Buil. 1936. La Jornada Internacional de la Mujer del 8 de marzo de 1936 fue una de las manifestaciones m├ís multitudinarias convocadas por las fuerzas de izquierda zaragozanas durante la Segunda Rep├║blica, con m├ís de 20.000 participantes. Al final del acto los organizadores entregaron al gobernador civil, ├üngel Vera Coronel, un manifiesto en el que reclamaban "el encarcelamiento de los responsables de la represi├│n de octubre de 1934 y una indemnizaci├│n para los familiares de las v├¡ctimas; trabajo o subsidio para los parados; el abaratamiento de las subsistencias y de los alquileres; la disoluci├│n y el desarme total de las bandas fascistas; contra la guerra y el fascismo; y por la libertad del pueblo abisinio". En la imagen, la manifestaci├│n se dirige por el Paseo Independencia hacia la sede del Gobierno Civil en la Plaza de Arag├│n, y pasa por la esquina con la calle Casa Jim├®nez. Entre la asistencia, la bandera constitucional, seguida de una pancarta de la Juventud Socialista Unificada, como unificaci├│n de la Uni├│n de Juventudes Comunistas y las Juventudes Socialistas. Habr├¡an de pasar varias d├®cadas para que el 8 de marzo recuperara su car├ícter reivindicativo, feminista, democr├ítico.', 1936, 1936, 1936, 'Anos 30', 'CENTRO', 41.64956300, -0.88380900, '0101000020E61000008522DDCF2948ECBF88D860E124D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15000151371.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15000151371.webp', 'https://www.flickr.com/photos/zaragozaantigua/15000151371/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25279, 'P.┬║ de la Independencia 1956', 'Foto Jos├® Antonio Duce, 1956. Vista desde el boulevard central del paseo de la Independencia, hacia la plaza Arag├│n. Operarios municipales riegan el firme. A la izquierda, edificio de Correos (1926). Fuente: www.gozazaragoza.com/contenido.php?id=9720 a trav├®s de www.facebook.com/photo.php?fbid=370948889728613&set=o...', 1956, 1956, 1956, 'Anos 50', 'CENTRO', 41.64936000, -0.88377200, '0101000020E61000003CDBA337DC47ECBF50AA7D3A1ED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15088170904.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15088170904.webp', 'https://www.flickr.com/photos/zaragozaantigua/15088170904/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25280, 'P.┬║ de la Independencia 1928', 'Acera de los pares del paseo de la Independencia en 1928, hacia la plaza de Arag├│n. Al fondo, edificio en reformas del n├║mero 32-34, entre las calles Casa Jim├®nez y Albareda, enfrente del edificio de Telef├│nica. Fuente: rt000z8y.eresmas.net/', 1928, 1928, 1928, 'Anos 20', 'CENTRO', 41.65020200, -0.88307600, '0101000020E6100000683D7C992842ECBF9BE5B2D139D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15222825257.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15222825257.webp', 'https://www.flickr.com/photos/zaragozaantigua/15222825257/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25283, 'La cabra de la Legi├│n 1982', 'Paso del Desfile del D├¡a de las Fuerzas Armadas por el paseo de la Independencia de Zaragoza en 1982. Al fondo, la plaza de Espa├▒a. En el centro de la imagen, la cabra de la Legi├│n, mascota de esta fuerza militar necr├│fila creada en 1920 por Jos├® Mill├ín-Astray. Fuente: www.facebook.com/photo.php?fbid=293499314182209&set=o...', 1982, 1982, 1982, 'Anos 80', 'CENTRO', 41.64972300, -0.88338800, '0101000020E61000001FB935E9B644ECBFC13A8E1F2AD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15283766167.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15283766167.webp', 'https://www.flickr.com/photos/zaragozaantigua/15283766167/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25291, 'P.┬║ de la Independencia 1956', 'C├®sar Gracia Jarque. 1956. "Paseo de la Independencia."', 1956, 1956, 1956, 'Anos 50', 'CENTRO', 41.64979500, -0.88326100, '0101000020E6100000D7A19A92AC43ECBF5A0D897B2CD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15754497980.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15754497980.webp', 'https://www.flickr.com/photos/zaragozaantigua/15754497980/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25298, 'Tako 1989', 'Foto: Vicente Jorcano para Heraldo de Arag├│n, 1989. Actuaci├│n del grupo ejeano de rock urbano Tako, en la sala M-Tro de Zaragoza, durante el concurso Medio Kilo de Rock en 1989. Fueron los ganadores. La sala M-Tro fue un local multidisciplinar, con exposiciones, tiendas de ropa, artesan├¡a, libros y discos, peluquer├¡a, oficina de fomento de autoempleo y unos bajos para actuaciones y proyecciones, con capacidad para 300 personas. Fue inaugurada en 1986. Fuente: www.facebook.com/zgz80s/photos/a.127459403989874.22917.12...', 1989, 1989, 1989, 'Anos 80', 'CENTRO', 41.64996300, -0.88445300, '0101000020E6100000BB2BBB60704DECBF164ED2FC31D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19269782166.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19269782166.webp', 'https://www.flickr.com/photos/zaragozaantigua/19269782166/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25299, 'Casa Pamplona 1927', 'Paseo Independencia y palacio de La Rosa, Luicien Roisin, 1927. El edificio de la derecha, en el paseo de la Independencia 29 y 31, es el antiguo palacio del bar├│n de La Rosa, que fue Capitan├¡a General entre 1867 y 1888. Era conocido como Casa Pamplona por ser su propietaria la familia Pamplona Escudero. Entre 1904 y 1910, los Hermanos Corazonistas ocuparon parte de sus dependencias. Luis Bu├▒uel vivi├│ all├¡ entre 1906 y 1917. Derribado en 1927, ocupan su solar las casas de Bruned (29, Heraldo de Arag├│n) y Escoriaza (31, esquina con la plaza de Santa Engracia). A la derecha, ebanister├¡a junto a las escaleras de acceso a la plaza. Fuente: "Zaragoza, a├▒os veinte. 81 fotograf├¡as de Roisin (1925-1931)", Instituci├│n Fernando el Cat├│lico, 2014.', 1927, 1927, 1927, 'Anos 20', 'CENTRO', 41.64979500, -0.88326100, '0101000020E6100000D7A19A92AC43ECBF5A0D897B2CD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20085029682.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20085029682.webp', 'https://www.flickr.com/photos/zaragozaantigua/20085029682/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25305, 'Correos 1936', 'Foto: Miguel Mar├¡n Chivite. Cuerpo de Carabineros a las puertas de Correos, en el paseo de la Independencia de Zaragoza, durante el intento de golpe de estado de julio de 1936. Fuente: Heraldo de Arag├│n.', 1936, 1936, 1936, 'Anos 30', 'CENTRO', 41.64936000, -0.88377200, '0101000020E61000003CDBA337DC47ECBF50AA7D3A1ED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20684498300.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20684498300.webp', 'https://www.flickr.com/photos/zaragozaantigua/20684498300/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25307, 'P.┬║ de la Independencia 1914', 'Manifestaci├│n de apoyo a los remolacheros convocada la tarde del 6 de marzo de 1914 y con recorrido desde la plaza del Pilar hasta la plaza de Arag├│n, sede del Gobierno civil. Tambi├®n se reivindic├│ la apertura del ferrocarril de Canfranc, vieja aspiraci├│n del gremio desde 1882, la construcci├│n del ferrocarril de Caminreal y los riegos del Alto Arag├│n. La imagen se ha capturado desde la altura del Quiosco de la m├║sica sito en el paseo de la Independencia con una buena vista en profundidad del mismo hasta la plaza de la Constituci├│n, al fondo.', 1914, 1914, 1914, 'Anos 10', 'CENTRO', 41.64964800, -0.88356400, '0101000020E6100000C2887D022846ECBFB6F468AA27D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21132643409.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21132643409.webp', 'https://www.flickr.com/photos/zaragozaantigua/21132643409/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25309, 'Tanques republicanos 1936', 'En abril de 1936, se celebraron festejos para conmemorar el quinto aniversario de la proclamaci├│n de la Rep├║blica. En la imagen, tanques desfilando ante el n├║mero 29 del paseo de la Independencia. En unos pocos meses... Fuente: Archivo Heraldo de Arag├│n.', 1936, 1936, 1936, 'Anos 30', 'CENTRO', 41.64979500, -0.88326100, '0101000020E6100000D7A19A92AC43ECBF5A0D897B2CD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21653570888.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21653570888.webp', 'https://www.flickr.com/photos/zaragozaantigua/21653570888/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25314, 'P.┬║ de la Independencia 1928', 'Paseo de la Independencia con el bulevar central. Al fondo, la plaza de la Constituci├│n. Fuente visual: Foto Conrado Barl├®s, donada por Daniel Barl├®s y digitalizada por Jos├® Luis Cintora para www.rafaelcastillejo.com', 1928, 1928, 1928, 'Anos 20', 'CENTRO', 41.64979500, -0.88326100, '0101000020E6100000D7A19A92AC43ECBF5A0D897B2CD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22877931939.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22877931939.webp', 'https://www.flickr.com/photos/zaragozaantigua/22877931939/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25321, 'Paseo Independencia c.1955', 'El paseo de la Independencia en el tramo de los edificios desde el n┬║ 31 y 29, a la derecha, dise├▒ados respectivamente por Miguel ├üngel Navarro P├®rez y por Teodoro R├¡os Balaguer, sobre la antigua gran casa del conde de la Rosa que a finales del siglo XIX acogi├│ provisionalmente la sede la Capitan├¡a General. A continuaci├│n, el singular inmueble conocido como casa Zapatero, situado entre las calles del Cardenal Garc├¡a Gil y de Felipe Sanclemente y que a├▒os m├ís tarde ser├¡a objeto de una moderna remodelaci├│n. Despu├®s, el gran edificio de viviendas de los n├║meros 23-25 dise├▒ado por Teodoro R├¡os Balaguer, y finalmente los bloques de viviendas del n┬║ 21 y el edificio del n┬║ 19 donde estaba radicada la sede de la Compa├▒├¡a de Seguros La Equitativa, ambos construidos recientemente sobre el antiguo convento de Jerusal├®n. Fuente visual: www.delcampe.net/', 1955, 1955, 1955, 'Anos 50', 'CENTRO', 41.65002300, -0.88296300, '0101000020E61000005F7F129F3B41ECBFEB5223F433D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23483984999.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23483984999.webp', 'https://www.flickr.com/photos/zaragozaantigua/23483984999/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25322, 'Cine Avenida 1968', 'Dibujo del acceso al cine Avenida, en el paseo de la Independencia 26. En su lugar hab├¡a estado el cine Alhambra entre 1911 y 1965. Fue inaugurado el 11 de mayo de 1968 seg├║n proyecto de Enrique Bas, y clausurado en enero de 1979 a la vez que el cine Actualidades. Fuente: www.rafaelcastillejo.com', 1968, 1968, 1968, 'Anos 60', 'CENTRO', 41.65023600, -0.88341200, '0101000020E6100000419B1C3EE944ECBF4757E9EE3AD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23641795301.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23641795301.webp', 'https://www.flickr.com/photos/zaragozaantigua/23641795301/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25328, 'Correos 1982', 'Unos tanques pasan ante el palco de autoridades, donde se sit├║a el rey Juan Carlos, durante la celebraci├│n del D├¡a de las Fuerzas Armadas de 1982. Al fondo, edificio de Correos en el paseo de la Independencia. Fuente: Agencia EFE.', 1982, 1982, 1982, 'Anos 80', 'CENTRO', 41.64964800, -0.88356400, '0101000020E6100000C2887D022846ECBFB6F468AA27D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24542780751.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24542780751.webp', 'https://www.flickr.com/photos/zaragozaantigua/24542780751/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25332, 'Calle Zurita c.1955', 'Imagen nocturna de la calle de Jer├│nimo Zurita a la altura del n├║mero 5. Al fondo, intersecci├│n con la de Isaac Peral. En la esquina, comercio de repuestos de autom├│viles Julio Gal├ín. Fuente: Colecci├│n Sergio Joven.', 1955, 1955, 1955, 'Anos 50', 'CENTRO', 41.65035500, -0.88157800, '0101000020E610000056F0DB10E335ECBF21E527D53ED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/26310725331.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/26310725331.webp', 'https://www.flickr.com/photos/zaragozaantigua/26310725331/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25354, 'Teatro Parisiana 1929', 'Imagen capturada en el interior del antiguo Teatro Parisiana, con un colectivo posado de la compa├▒├¡a de teatro formada recientemente por Irene Alba y Joaqu├¡n Garc├¡a Le├│n, caracterizada para la representaci├│n de la obra "Ramo de locura", escrita por los hermanos Seraf├¡n y Joaqu├¡n ├ülvarez Quintero. Figuran, de izquierda a derecha, y de arriba a abajo, Joaqu├¡n Garc├¡a Le├│n, Mar├¡a Pujol, Marcial Manent, Pablo Hidalgo, Mercedes Prendes, Irene Alba, Valentina Iparraguirre, Julia Caba y Emilio Guti├®rrez Esteban. Algunas de las m├ís que notables figuras del pasado, presente, y futuro de la escena espa├▒ola. El Teatro Parisiana estaba ubicado en el paseo de la Independencia n┬║ 23, con acceso secundario por la calle de Felipe Sanclemente. En 1934 fue derribado y sustituido por un nuevo recinto de espect├ículos que abri├│ sus puertas en 1935 con la denominaci├│n "Nuevo Teatro Parisiana", hasta que en 1938 fue obligado a espa├▒olizar su nombre cuando los ni├▒os ya no ven├¡an de Par├¡s, sino de Berl├¡n. Desde entonces, y hasta su definitivo cierre a finales de los a├▒os ochenta del pasado siglo, fue el Teatro Argensola. Fuente visual: www.mecd.gob.es/.', 1929, 1929, 1929, 'Anos 20', 'CENTRO', 41.65011800, -0.88238100, '0101000020E6100000AB933314773CECBF3D450E1137D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/34418514784.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/34418514784.webp', 'https://www.flickr.com/photos/zaragozaantigua/34418514784/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25356, 'P.┬║ Independencia 1935', 'Imagen capturada durante el desfile militar incluido en el programa de actos de homenaje al aniversario IV de la proclamaci├│n de la Segunda Rep├║blica. La castrense muestra se realiz├│ sobre un recorrido que se iniciaba en la Gran V├¡a, segu├¡a por la plaza de Arag├│n, paseo de la Independencia, plaza de la Constituci├│n, Coso, calle del Conde Aranda, y finalizaba en la plaza del Portillo. En ella participaron fuerzas de la guarnici├│n (infanter├¡a, carros de combate, artille┼ò├¡a, zapadores, caballer├¡a, pontoneros, intendencia, sanidad), Guardia civil, Fuerzas de Seguridad y Asalto, y Cruz Roja. En la imagen, mientras desfilan tropas del regimiento n┬║ 5 de infanter├¡a, y a la izquierda, la tribuna de autoridades e invitados instalada en la plaza de Santa Engracia. Fuente visual: www.mecd.gob.es/.', 1935, 1935, 1935, 'Anos 30', 'CENTRO', 41.64958900, -0.88341100, '0101000020E61000002AA73D25E744ECBFB16B7BBB25D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/36146755940.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/36146755940.webp', 'https://www.flickr.com/photos/zaragozaantigua/36146755940/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25359, 'P.┬║ de la Independencia 1935', 'Imagen capturada en el paseo de la Independencia durante la conmemoraci├│n oficial del 4.┬║ aniversario de la proclamaci├│n de la Segunda Rep├║blica espa├▒ola, con fuerzas de la guarnici├│n de Zaragoza desfilando en el tramo del paseo entre la calle de Jer├│nimo Zurita y la plaza de Santa Engracia. Fuente visual: diario gr├ífico Ahora (Madrid).', 1935, 1935, 1935, 'Anos 30', 'CENTRO', 41.65027000, -0.88257400, '0101000020E6100000D09849D40B3EECBFF3C81F0C3CD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/38732093190.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/38732093190.webp', 'https://www.flickr.com/photos/zaragozaantigua/38732093190/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25371, 'P┬║. Independencia c.1935', 'Imagen capturada en el interior de la zona de porches del gran inmueble del n┬║ 30-32 del paseo de la Independencia (actual n┬║ 34), donde desde 1881 estaba ubicado el Gran Caf├® Ambos Mundos, que aqu├¡ presenta su acristalada fachada de casi 40 metros de largo, e ingreso principal. Los grandes ventanales, que aqu├¡ aparecen decorados con grandes maceteros, permit├¡an un importante acceso de luz natural para tan grande espacio interior con capacidad de hasta 1.800 personas... Fue finalmente cerrado en 1955. Desde 1889 las plantas superiores estaban ocupadas por el Banco de Cr├®dito de Zaragoza, desde 1928 remodeladas en profundidad por el arquitecto Pascual Bravo Sanfeli├║.', 1935, 1935, 1935, 'Anos 30', 'CENTRO', 41.64939400, -0.88427000, '0101000020E610000079AF5A99F04BECBFFC1BB4571FD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51375214938.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51375214938.webp', 'https://www.flickr.com/photos/zaragozaantigua/51375214938/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25372, 'P.┬║ de la Independencia 1956', 'Imagen capturada una fresca ma├▒ana de invierno en el paseo de la Independencia y a la altura de la plaza de Santa Engracia durante el tr├ínsito de una singular caravana comercial de "Mistol", formada por motocicleta, utilitario, furgoneta y camioneta, recorriendo el centro de la ciudad para promocionar el consumo de este producto. Al fondo, el esquinero edificio de Correos y tel├®grafos. En primer t├®rmino, adoquinado y v├¡as del tranv├¡a por donde circulaban las l├¡nea 5. "Venecia-Delicias", 11. "Parque" y 15. "Casablanca".', 1956, 1956, 1956, 'Anos 50', 'CENTRO', 41.64960300, -0.88331500, '0101000020E6100000A31EA2D11D44ECBF1631EC3026D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51674469989.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51674469989.webp', 'https://www.flickr.com/photos/zaragozaantigua/51674469989/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25375, 'P.┬║ de la Independencia c.1957', 'Imagen desde cierta altura del arbolado bulevar de toda la vida del paseo de la Independencia orientado hacia su arranque desde la plaza de Espa├▒a, al fondo. A la derecha, ingreso a la plaza de Santa Engracia y edificio de Correos. Sobre el firme de la izquierda, coche de la serie 200 en servicio en la tranviaria l├¡nea 11, Parque encaminado hacia la terminal sita en la plaza del Emperador Carlos V.', 1957, 1957, 1957, 'Anos 50', 'CENTRO', 41.64953000, -0.88371200, '0101000020E6100000E8A562635E47ECBFACE28DCC23D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/54166363679.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/54166363679.webp', 'https://www.flickr.com/photos/zaragozaantigua/54166363679/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25809, 'Calle San Miguel 1973', 'Esta fue durante 75 a├▒os la esquina del Teatro Circo entre las calles de San Miguel y la de los Sitios (luego, Isaac Peral). Tras su demolici├│n en 1962, form├│ parte de un moderno edificio, el actual, en cuyos bajos se instal├│ la sucursal de una entidad local de ahorro. En el corporativo y acristalado chafl├ín, destellean desde la otra esquina de la calle de San Miguel, unos casuales reflejos del cine Goya, vecino del Teatro Circo durante casi treinta a├▒os. Ninguno de los perdura. La sucursal, s├¡. Como bien dice el comercial de la imagen, que nuestros ingresos tienen premios bien lo saben las entidades de dep├│sito de ahorro. Abrumadoramente, para ellas, aunque te se├▒alen con el dedo. Fuente visual: Gerardo Sancho Ramo, Archivo Municipal de Zaragoza.', 1973, 1973, 1973, 'Anos 70', 'CENTRO', 41.65087900, -0.88040700, '0101000020E6100000516C054D4B2CECBF9C53C90050D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/25263114185.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/25263114185.webp', 'https://www.flickr.com/photos/zaragozaantigua/25263114185/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25602, 'Perico Fern├índez y Pel├® 1974', 'Archivo Municipal de Zaragoza. Gerardo Sancho Ramo. 03/09/1974. "F├║tbol. Zaragoza 2 - Santos de Brasil 3." Un partido amistoso de f├║tbol jugado en el estadio municipal de la Romareda, entre los clubs del "Real Zaragoza" y el "Santos de Brasil", el 3 se setiembre de 1974. En la imagen, saque de honor a cargo de Perico Fern├índez, campe├│n mundial de boxeo en la categor├¡a de pesos ligeros de ese a├▒o. A su derecha, Edson Arantes do Nascimento, m├ís conocido como Pel├®.', 1974, 1974, 1974, 'Anos 70', 'UNIVERSIDAD', 41.63664600, -0.90197300, '0101000020E610000011001C7BF6DCECBF8A90BA9D7DD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15126488940.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15126488940.webp', 'https://www.flickr.com/photos/zaragozaantigua/15126488940/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25813, 'Teatro Circo 1895', 'Espectacular imagen capturada tras el incendio del Teatro Circo de febrero de 1895. Inaugurado en octubre de 1887 con dise├▒o del arquitecto Ricardo Magdalena Tabuenca, fue construido sobre un solar hasta entonces ocupado por unos lavaderos p├║blicos. Este incendio devast├│ el teatro, aunque afortunadamente el siniestro tuvo lugar fuera del horario de funciones y no produjo da├▒os personales. Su propietario, Manuel Marraco Rocatallada, pudo reconstruirlo inmediatamente gracias al dinero del seguro, de forma que para las Fiestas del Pilar de ese mismo a├▒o el Teatro Circo ya pudo reabrirse al p├║blico. La instant├ínea recoge el estado de su devastado interior tras el incendio, destacando en la parte superior el esqueleto de la armadura de hierro del techo. A la izquierda, restos del escenario, y a la derecha, de la platea y anfiteatro. En primer t├®rmino, el patio de butaca consumido por el fuego. Al fondo y a la derecha emerge la chimenea de la Electro Peral Zaragozana, instalada desde 1893 en el original Teatro Goya de Zaragoza (1882-1893), y recayente a un vial que conduc├¡a a la Huerta de Santa Engracia y que a├▒os despu├®s recibir├¡a el nombre de Isaac Peral por la presencia de esta el├®ctrica instalaci├│n. El singular hallazgo de la original y fracturada placa fotogr├ífica de cristal de esta imagen, restaurada por Julio S├ínchez Mill├ín, ha permitido datar correctamente esta fotograf├¡a, hasta ahora asociada al derribo del Teatro Circo en 1962.', 1895, 1895, 1895, 'Siglo XIX', 'CENTRO', 41.65079700, -0.88044000, '0101000020E61000003FE3C281902CECBFDEAAEB504DD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50082592023.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50082592023.webp', 'https://www.flickr.com/photos/zaragozaantigua/50082592023/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25865, 'Teatro Pignatelli 1878', 'Vista del Teatro Pignatelli, en la calle de la Independencia. Fuente: Foto para postal de Comercial Josan. Cesi├│n de la familia de Jos├® Mar├¡a Sanz Gonz├ílez a Rafael Castillejo. Dataci├│n y procesado:', 1878, 1878, 1878, 'Siglo XIX', 'CENTRO', 41.64979500, -0.88326100, '0101000020E6100000D7A19A92AC43ECBF5A0D897B2CD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/26796673113.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/26796673113.webp', 'https://www.flickr.com/photos/zaragozaantigua/26796673113/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25920, 'P.┬║ de la Independencia c.1952', 'Imagen capturada desde cierta altura, posiblemente desde el edificio de Correos, de la solana del antiguo paseo de la Independencia, desde el emboque a la calle del Marqu├®s de Casa Jim├®nez, y hasta la plaza de Espa├▒a, al fondo, a la derecha. A la izquierda, el bloque del n┬║ 30, sede del Banco Central. Inmediato, y en el paseo, el quiosco P├│rtico, con publicidad del prestigioso producto "Libel" de Jabones Barang├®, para el "lavado perfecto de prendas finas". Encaminado hacia la plaza de Arag├│n, una de las primeras unidades de la serie 200, en servicio en la tranviaria l├¡nea Parque. Al otro lado del paseo, una composici├│n tranviaria posiblemente transita desde Venecia hacia Delicias. Fuente visual: Editorial Garc├¡a Garrabella, en www.todocoleccion.net/', 1952, 1952, 1952, 'Anos 50', 'CENTRO', 41.64951900, -0.88354300, '0101000020E6100000E48233F8FB45ECBFB890477023D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31769085620.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31769085620.webp', 'https://www.flickr.com/photos/zaragozaantigua/31769085620/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23266, 'El Portillo 1808', '"Combate de las zaragozanas con los dragones franceses. En el ataque del 15 de Junio 200 dragones franceses pudieron penetrar en la Ciudad y fueron rechazados y muertos por el pueblo. Cinco de ellos, que van a escaparse por la puerta del Portillo, son embestidos por un tropel de Mujeres valientes y perecen a sus manos". Serie Ruinas de Zaragoza, de Juan G├ílvez (dibujo) y Fernando Brambila (grabado), C├ídiz, 1812. Momento en que cinco dragones (soldados de la caballer├¡a francesa con coraza, sable y penacho en la cabeza) que hab├¡an entrado por la Puerta del Carmen, intentan escapar cuando caen en que con cinco no van muy lejos, y son atacados por una desmesurada cantidad de zaragozanas en la desaparecida plaza del Portillo. Esta acci├│n se desarroll├│ el 15 de junio de 1808. Fuente visual: bvpb.mcu.es/', 1808, 1808, 1808, 'Siglo XIX', 'CENTRO', 41.65581700, -0.89219100, '0101000020E61000001C23D923D48CECBF9694BBCFF1D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15080217829.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15080217829.webp', 'https://www.flickr.com/photos/zaragozaantigua/15080217829/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23933, 'Plaza de Toros 1904', 'Plaza de Toros de Zaragoza en 1904. Sobresalen por detr├ís las torres y la c├║pula de la iglesia de la Casa de la Misericordia. Fuente: Revista "La fiesta nacional", Barcelona, 1904.', 1904, 1904, 1904, 'Anos 1900', 'CENTRO', 41.65491600, -0.89129900, '0101000020E6100000DFA3FE7A8585ECBF46D09849D4D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24431350312.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24431350312.webp', 'https://www.flickr.com/photos/zaragozaantigua/24431350312/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23938, 'Plaza de Toros c.1964', 'Vista de la Plaza de Toros de La Misericordia en la plaza del Portillo. Al fondo, torres y c├║pula de la iglesia del Hogar Pignatelli. Fuente: Foto para postal de Comercial Josan. Cesi├│n de la familia de Jos├® Mar├¡a Sanz Gonz├ílez a Rafael Castillejo. Dataci├│n y procesado:', 1964, 1964, 1964, 'Anos 60', 'CENTRO', 41.65492400, -0.89209200, '0101000020E610000051BEA085048CECBFC9AEB48CD4D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/27418455015.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/27418455015.webp', 'https://www.flickr.com/photos/zaragozaantigua/27418455015/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23948, 'El Portillo c.1903', 'Imagen capturada desde la altura de la iglesia de N┬¬. S┬¬. del Portillo y centrada en la zona del antiguo Campo del Toro, donde destaca el coso de la Misericordia con su aspecto previo a la gran remodelaci├│n de 1916. A su derecha, la Casa Inclusa y el cuartel de caballer├¡a del Cid. A la izquierda, arranque de la calle de Ram├│n Pignatelli desde la plaza del Portillo. De fondo, la gran estructura del Hospicio Provincial, del que emergen las torrecillas y la neobizantina c├║pula de su iglesia.', 1903, 1903, 1903, 'Anos 1900', 'CENTRO', 41.65496600, -0.89195200, '0101000020E6100000E141B3EBDE8AECBFF8FE06EDD5D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51461673787.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51461673787.webp', 'https://www.flickr.com/photos/zaragozaantigua/51461673787/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (20889, 'Anfiteatro siglo I', 'Mapa de situaci├│n del anfiteatro romano de Zaragoza, construido en el siglo I de nuestra Era, seg├║n Miguel Beltr├ín, director del Museo de Zaragoza, 2009. La ubicaci├│n propuesta tiene como centro actual el Hotel Palafox y est├í ubicada entre las calles Antonio Valcarreres, Marceliano Is├íbal, Bilbao, Albareda y avenida C├®sar Augusto. Sin embargo, un art├¡culo de 2012 (www.academia.edu/3687122/Una_nueva_hip%C3%B3tesis_sobre_l...) situaba el anfiteatro en la actual plaza de los Sitios, hip├│tesis que fue rechazada por alg├║n experto aduciendo restos de construcciones de la Exposici├│n Hispano Francesa de 1908. Ver plano de situaci├│n alternativo aqu├¡: www.flickr.com/photos/zaragozaantigua/15906334241/. En el estudio "Nuevas cuestiones sobre el anfiteatro de Zaragoza" (2016), de Jos├® David Mendoza: www.um.es/cepoat/pantarei/wp-content/uploads/2016/10/pant..., se descartan ambas ubicaciones. Fuente: www.heraldo.es/noticias/cultura/el_anfiteatro_cesaraugust...', 50, NULL, 99, 'Siglo XIX', 'CENTRO', 41.65045600, -0.88550200, '0101000020E6100000EA5C514A0856ECBF55BE672442D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15725380705.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15725380705.webp', 'https://www.flickr.com/photos/zaragozaantigua/15725380705/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21014, 'Monumento a Pignatelli 1867', '"Monumento a Pignatelli", xilograf├¡a de Tom├ís Carlos Capuz incluida en la Cr├│nica general de Espa├▒a, Madrid, 1867.', 1867, 1867, 1867, 'Siglo XIX', 'CENTRO', 41.64836500, -0.88495900, '0101000020E6100000AEA069899551ECBF7E6FD39FFDD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/18911975194.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/18911975194.webp', 'https://www.flickr.com/photos/zaragozaantigua/18911975194/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21019, 'Exposici├│n Aragonesa 1868', '"Exposici├│n aragonesa. Proyecto del edificio principal y de disposici├│n de las dem├ís dependencias". Mariano Utrilla, Zaragoza, 1868. Plano de la Exposici├│n Aragonesa de 1868 en Zaragoza, en la Glorieta de Pignatelli. Se celebr├│ de septiembre a noviembre. Fuente: AMZ.', 1868, 1868, 1868, 'Siglo XIX', 'CENTRO', 41.64836500, -0.88495900, '0101000020E6100000AEA069899551ECBF7E6FD39FFDD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19634933925.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19634933925.webp', 'https://www.flickr.com/photos/zaragozaantigua/19634933925/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21036, 'Exposici├│n Aragonesa 1868', 'La Sociedad Econ├│mica Aragonesa de Amigos del Pa├¡s organiz├│ en 1868 la Exposici├│n Aragonesa de Agricultura, la Industria y las Artes, en la Glorieta de Pignatelli de Zaragoza. En la imagen, placa de bronce de 24 cm, conmemorativa del evento. Fuente: www.todocoleccion.net', 1868, 1868, 1868, 'Siglo XIX', 'CENTRO', 41.64845800, -0.88489700, '0101000020E61000002C836A831351ECBF2F6AF7AB00D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30709917382.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30709917382.webp', 'https://www.flickr.com/photos/zaragozaantigua/30709917382/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21056, 'Ram├│n Pignatelli c.1877', 'Archivo RUIZ VERNACCI, Jean Laurent y C├¡a. 1860-1886. "Estatua de Pignatelli". Glorieta de Pignatelli.. Ram├│n Pignatelli (1734-1793), pol├¡tico zaragozano ilustrado, impulsor del Canal Imperial de Arag├│n.', 1877, 1877, 1877, 'Siglo XIX', 'CENTRO', 41.64830400, -0.88486000, '0101000020E6100000E23B31EBC550ECBFD9EE1EA0FBD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14864310894.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14864310894.webp', 'https://www.flickr.com/photos/zaragozaantigua/14864310894/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21146, 'Capitan├¡a General 1893', 'AHPZ. Estudio Coyne. 1893. "Capitan├¡a General." Entre 1879 y 1893 se levant├│ en la Glorieta de Pignatelli el nuevo edificio de la Capitan├¡a General, que se traslad├│ a esta ubicaci├│n de la anterior en que estaba, en un antiguo palacio dieciochesco del Coso Medio.', 1893, 1893, 1893, 'Siglo XIX', 'CENTRO', 41.64816800, -0.88569700, '0101000020E61000003C4A253CA157ECBF2828452BF7D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15208551974.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15208551974.webp', 'https://www.flickr.com/photos/zaragozaantigua/15208551974/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21189, 'Plaza de Arag├│n 1893', 'In├®dita y luminosa imagen de la plaza de Arag├│n capturada desde la relativa altura del reci├®n inaugurado "Nuevo Palacio para Capitan├¡a general de Arag├│n" (sic). En primer t├®rmino y a la izquierda, v├¡as de la l├¡nea de Torrero de la red tranviaria de tracci├│n animal, en este caso las encaminadas hacia la Playa de Torrero. En el centro de la frondosa plaza, el Monumento a Pignatelli, y de fondo edilicio, las fachadas principales de los orientales hotelitos de los n├║meros 1 a 7 de la plaza, con una muestra de su aspecto casi original, luego bastante transformado, hasta su progresiva extinci├│n no natural en la segunda mitad del siglo XX. As├¡, y de izquierda a derecha, el hotelito del n┬║ 1 dise├▒ado por Antonio Miranda y ya transformado por Fernando de Yarza Fern├índez-Trevi├▒o para el industrial Tom├ís Castellano Villarroya. Los hotelitos n┬║ 2, 3 y 4 aqu├¡ se muestran como lo que fueron en un principio: id├®nticas viviendas unifamiliares proyectadas de forma seriada por F├®lix Navarro P├®rez. Tras la calle de Puigcerd├í, el hotelito del n┬║ 5, proyectado por Manuel Ruiz; el n┬║ 6, proyectado por Eusebio Lid├│n Barra, ya recrecido en una altura respecto al original; finalmente y a la derecha, vista parcial del n┬║ 7, proyectado por Fernando de Yarza Fern├índez-Trevi├▒o en aires inequ├¡vocamente franceses. A la izquierda y tras la calle de Juan Bruil, la gran estructura del Teatro Pignatelli, por encima del que sobresale la ├║nica torre de la iglesia parroquial de Santa Engracia, y tras la hom├│nima plaza, vista de la gran casa del conde de La Rosa.', 1893, 1893, 1893, 'Siglo XIX', 'CENTRO', 41.64836800, -0.88486000, '0101000020E6100000E23B31EBC550ECBFEFE2FDB8FDD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50086764277.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50086764277.webp', 'https://www.flickr.com/photos/zaragozaantigua/50086764277/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21191, 'Glorieta de Pignatelli c.1890', 'Imagen capturada en la glorieta de Pignatelli y centrada en el hom├│nimo monumento que desde 1859 luc├¡a en este espacio que jalonaba la direcci├│n del ensanche de la ciudad por el sur. Hacia el fondo y en perspectiva, edificaciones del paseo de la Independencia, a la izquierda los que pretend├¡an rememorar la parisina y porticada "rue de Rivoli", y a la derecha el tramo que hasta la plaza de Santa Engracia determinaba la gr├ícil estructura del Teatro Pignatelli, y que m├ís all├í culmina el remate de la barroca torre de la Seo. En primer t├®rmino y a la derecha, un auxiliar del fot├│grafo aparta sutilmente con una gayata unos juncales para despejar la vista de la base del monumento, aunque para ello se mete en el encuadre resultando as├¡ una estampa muy zaragozana.', 1890, 1890, 1890, 'Siglo XIX', 'CENTRO', 41.64838400, -0.88485000, '0101000020E6100000FFB27BF2B050ECBFF59F353FFED24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50120055002.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50120055002.webp', 'https://www.flickr.com/photos/zaragozaantigua/50120055002/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21270, 'Plaza de Arag├│n 1903', 'Imagen de la plaza de Arag├│n cuando el inquilino ilustrado, Don Ram├│n Pignatelli, estaba apurando el contrato de permanencia, antes de deslocalizarse Paseo de Sagasta arriba, y ser sustituido por otro inquilino, este sedente, y medieval. Detr├ís, la calle de la Independencia y la plaza de Santa Engracia. Delante, un muchacho comenzando la carrera de Don Tancredo. Fuente visual: Postal de la colecci├│n &quot;Arag├│n&quot;, serie &quot;Zaragoza&quot; (n┬║ 14, Estatua de Pignatelli) del librero Cecilio Gasca. Huecograbado impreso en color azul.', 1903, 1903, 1903, 'Anos 1900', 'CENTRO', 41.64836500, -0.88495900, '0101000020E6100000AEA069899551ECBF7E6FD39FFDD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21923194505.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21923194505.webp', 'https://www.flickr.com/photos/zaragozaantigua/21923194505/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21289, 'Glorieta de Pignatelli c.1900', 'Tarjeta postal centrada en el edificio de la nueva Capitan├¡a General sito en la glorieta de Pignatelli. A la izquierda, el paseo de le Lealtad. A la derecha, uno de los hotelitos edificado sobre los terrenos de la Exposici├│n Aragonesa de 1885. Fuente: Fototipia Hauser y Menet, en www.ebay.es/', 1900, 1900, 1900, 'Anos 1900', 'CENTRO', 41.64816800, -0.88569700, '0101000020E61000003C4A253CA157ECBF2828452BF7D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/26544808425.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/26544808425.webp', 'https://www.flickr.com/photos/zaragozaantigua/26544808425/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21353, 'Glorieta de Pignatelli 1900', 'Luminosa imagen capturada en la glorieta de Pignatelli cuando esta segu├¡a siendo la principal zona verde de la ciudad. Fue trazada en 1840 en este espacio de transici├│n entre el Sal├│n de Santa Engracia y la puerta y puente hom├│nimos, vertebrada como ilustra la fotograf├¡a en torno a la estatua del pr├│cer local Ram├│n Pignatelli tallada por Antonio Palao Marco e inaugurada en 1859. Tras la Exposici├│n Aragonesa de 1868 que se ubic├│ aqu├¡, el terreno fue distribuido en manzanas cuyos solares terminaron vendidos, por causa de la mala situaci├│n econ├│mica del Ayuntamiento, a algunas de las familias m├ís poderosas de la ciudad que construyeron en este selecto espacio destacados hotelitos particulares. En la escena puede verse a la derecha el hotelito de Tom├ís Castellano Villarroya y dos de los hotelitos pareados proyectados por F├®lix Navarro P├®rez. Al fondo y de izquierda a derecha, edificios de la calle de la Independencia, el Teatro Pignatelli y la iglesia de Santa Engracia con su torre lateral reconstruida poco antes.', 1900, 1900, 1900, 'Anos 1900', 'CENTRO', 41.64814400, -0.88510700, '0101000020E6100000D3BD4EEACB52ECBFA08CF161F6D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/54773818688.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/54773818688.webp', 'https://www.flickr.com/photos/zaragozaantigua/54773818688/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21399, 'Calle de Valencia 1913', 'Imagen de postal capturada desde la cima de la Facultad de Medicina, que entonces era atalaya privilegiada para contemplar los tejados de la ciudad. La visual est├í orientada hacia el el noreste, siguiendo la l├¡nea que marca la calle de Valencia (luego, Bilbao), hasta Casa Jim├®nez, con el edificio de Capitan├¡a General a la derecha, y la f├íbrica de conservas "Besc├│s Hermanos" a la izquierda. Esta f├íbrica "a vapor" estaba especializada en "art├¡culos finos para fondas y restaurantes", cuando en la ciudad hab├¡a una destacada n├│mina de este tipo de factor├¡as (Delatas y Compa├▒├¡a, Antonio Burillo, Cort├®s Gus├® y C├¡a, Manuel Marraco...) A la derecha, y en paralelo, tras la plaza de Arag├│n, el arbolado paseo de la Independencia, en el tramo de la plaza de Santa Engracia, con el palacete del bar├│n de la Rosa a un lado, y los nuevos porches del paseo a├║n sin el previsto edificio de Correos encima, al otro. Al fondo, La Seo, San Gil, y el Pilar. Fuente visual: Lucien Levy fils.', 1913, 1913, 1913, 'Anos 10', 'CENTRO', 41.64818600, -0.88611400, '0101000020E610000047E350BF0B5BECBFCFDC43C2F7D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21593018713.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21593018713.webp', 'https://www.flickr.com/photos/zaragozaantigua/21593018713/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21403, 'Conservas Besc├│s 1910', 'Imagen publicitaria de la f├íbrica de conservas vegetales de Mariano Besc├│s, luego Besc├│s Hermanos, que se instal├│ en Zaragoza hacia 1900, permaneciendo all├¡ durante m├ís de tres d├®cadas. En el centro del dibujo, la factor├¡a del paseo de Pamplona, entre las calles de Ponciano Ponzano y Bilbao. Fuente visual: www.todocoleccion.net', 1910, 1910, 1910, 'Anos 10', 'CENTRO', 41.64827900, -0.88635300, '0101000020E610000082C476F7005DECBF80D767CEFAD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23975209680.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23975209680.webp', 'https://www.flickr.com/photos/zaragozaantigua/23975209680/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21437, 'Plaza Arag├│n 1915', 'Paso por el ala oeste de la plaza de Arag├│n de la carroza del Ayuntamiento de Zaragoza, precedida de ni├▒os exploradores con sus banderas y singulares sombreros, en el desfile de las fiestas del Pilar de 1915.', 1915, 1915, 1915, 'Anos 10', 'CENTRO', 41.64873900, -0.88487000, '0101000020E6100000C6C4E6E3DA50ECBFE3512AE109D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/43360932091.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/43360932091.webp', 'https://www.flickr.com/photos/zaragozaantigua/43360932091/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21452, 'Plaza de Arag├│n 1915', 'Imagen capturada desde la altura del inmueble del n┬║ 13 de la plaza de Arag├│n con una interesante vista de este tradicional espacio urbano de esparcimiento. De la frondosa isleta central emerge el Monumento al Justiciazgo, y al otro lado de la plaza se nos muestra el tramo edilicio desde la calle de Puigcerd├í, a la izquierda, con una vista completa de los "hotelitos" de los n├║meros 5 a 8. Tras ellos la trinchera del r├¡o Huerva y el gran edificio del colegio del Salvador. A la derecha y al fondo, la facultad de Medicina y Ciencias junto al puente de Santa Engracia que da acceso al paseo de Sagasta.', 1915, 1915, 1915, 'Anos 10', 'CENTRO', 41.64897700, -0.88482800, '0101000020E61000000AB952CF8250ECBF986DA7AD11D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51696244542.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51696244542.webp', 'https://www.flickr.com/photos/zaragozaantigua/51696244542/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21518, 'Calle de Bilbao 1922', 'Archivo Burges. 1922. "Juegos Ol├¡mpicos" organizados por la FASD (Federaci├│n Aragonesa de Sociedades Deportivas), con el objetivo de abarcar a todo el territorio regional, e integrar a todos los deportes, en el campo de f├║tbol de la calle de Bilbao. Su vida ser├í breve. En la imagen, prueba de salto de altura de esos "Juegos Ol├¡mpicos". Al fondo, edificios de la calle Bilbao: las viviendas, a la derecha (superviven), y las instalaciones del Gobierno Militar en el antiguo Convento de las Descalzas de San Jos├®, a la izquierda (superviven, como instalaciones municipales). Fuente: Pedro Ciria Amores "El sue├▒o de ser grandes: Historia social del nacimiento del f├║tbol en Zaragoza, 1903-1936".', 1922, 1922, 1922, 'Anos 20', 'CENTRO', 41.64953000, -0.88592200, '0101000020E610000039D219187959ECBFACE28DCC23D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15943587556.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15943587556.webp', 'https://www.flickr.com/photos/zaragozaantigua/15943587556/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23996, 'Base A├®rea 2003', 'Foto: Javier Belver Pese a que en 1992 las fuerzas armadas estadounidenses abandonaron oficialmente la Base A├®rea de Zaragoza, ├®sta sigui├│ ofreciendo apoyo log├¡stico al ej├®rcito de ese pa├¡s. En la imagen, una marcha convocada como protesta en el marco de la Guerra de Irak, el 30 de marzo de 2003. Fuente: European Pressphoto Agency.', 2003, 2003, 2003, 'Siglo XXI', NULL, 41.66578500, -1.06859900, '0101000020E6100000E59CD843FB18F1BF6C95607138D54440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20876334941.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20876334941.webp', 'https://www.flickr.com/photos/zaragozaantigua/20876334941/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21569, 'Plaza de Arag├│n c.1920', 'Los d├¡as de niebla (en cualquiera de sus denominaciones) en Zaragoza son bastantes introspectivos, como ensimismados. El aire fr├¡o y h├║medo, sin circulaci├│n atmosf├®rica que lo perturbe, en ocasiones parece empadronarse, y nos acompa├▒a varias jornadas. Es un fen├│meno que ralentiza el tiempo, como la imagen ilustra, en una apacible ma├▒ana de la plaza de Arag├│n, cuando un tranquilo paseo sintoniza con el silencio apenas alterado por palabras susurradas. El paisaje urbano se difumina, sus perfiles se suavizan, y la ciudad se acurruca en s├¡ misma, en el fondo, y en la forma. Al fondo, en el paseo de la Independencia, los ecos del traqueteo tranviario resuenan leves, como entre algodones. Fuente visual: Archivo Julio Requejo (DARA-AHPZ)', 1920, 1920, 1920, 'Anos 20', 'CENTRO', 41.64841500, -0.88489300, '0101000020E6100000D1B2EE1F0B51ECBF309E4143FFD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23632887120.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23632887120.webp', 'https://www.flickr.com/photos/zaragozaantigua/23632887120/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21594, 'General Sanjurjo 1926', 'El 12 de octubre de 1926, la Dictadura de Primo de Rivera decret├│ la celebraci├│n de la "Fiesta de la Paz y Homenaje al Ej├®rcito", por el feliz t├®rmino de las campa├▒as de Marruecos. En Zaragoza, la coincidencia con el d├¡a de la Virgen del Pilar, reforz├│ a├║n m├ís los lazos "Pilar, Raza, Patria". Ese d├¡a visitaron la ciudad los generales Primo de Rivera, Sanjurjo, adem├ís de varios ministros y personalidades, protagonizando una apretada agenda de actos que comenz├│ de buena ma├▒ana con un solemne "Ted├®um" en el Pilar, y un responso "por los muertos de ├üfrica" (los propios). Acto seguido, la comitiva se dirigi├│ a la hasta entonces calle de la Soberan├¡a Nacional, para descubrir una l├ípida que escenificaba el cambio de su nomencl├ítor por "General Sanjurjo", que adem├ís recibi├│ el t├¡tulo de "Hijo Adoptivo de Zaragoza". En la imagen, descubierta l├ípida de la nueva calle, tallada de forma singular, sobre los muros del Cuartel del Carmen, en la esquina de la antigua Soberan├¡a Nacional-nueva General Sanjurjo. Con la llegada de la democracia, en 1931, esta calle recuper├│ su denominaci├│n anterior, aunque tras el 18 de julio de 1936, la Soberan├¡a Nacional fue desaparecida por segunda vez (signo de los tiempos), siendo sustituida nuevamente por el General Sanjurjo, en el tramo desde la puerta del Carmen a Ram├│n y Cajal, y a├▒os despu├®s por el blaudivisionario en Rusia, Capit├ín Portol├®s, en el tramo hasta la plaza del Carmen. Fuente visual: Alejandro de la Barrera, Archivo Municipal de Zaragoza.', 1926, 1926, 1926, 'Anos 20', 'CENTRO', 41.65087900, -0.88485900, '0101000020E6100000CB4752D2C350ECBF9C53C90050D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24873795905.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24873795905.webp', 'https://www.flickr.com/photos/zaragozaantigua/24873795905/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21696, 'Plaza de Arag├│n A├▒os 30', 'AHPZ. Estudio Coyne. A├▒os 30. La plaza de Arag├│n fue dise├▒ada con planta de "par├®ntesis", con estatua en medio; Pignatelli, primero, Lanuza, luego. En la imagen, aspecto del par├®ntesis izquierdo (desde el punto de vista de esta imagen) del que arranca la calle Canfranc (hacia la izquierda), y los hotelitos que la mojoneaban, hasta que fueron (menos uno) procesados d├®cadas despu├®s por la piqueta del capitalismo de nuevo signo, vertical, imponente, despiadado.', 1930, 1930, 1939, 'Anos 30', 'CENTRO', 41.64846400, -0.88537500, '0101000020E6100000A245B6F3FD54ECBF11514CDE00D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15377547151.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15377547151.webp', 'https://www.flickr.com/photos/zaragozaantigua/15377547151/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21732, 'Calle Albareda 1933', 'El 26 de junio de 1933 el Front├│n Aragon├®s fue escenario de un mitin convocado por el partido "Comuni├│n Tradicionalista de Zaragoza". Lleno a rebosar con tradicionalistas de toda la provincia, amenizaba la tradicionalista banda de Novallas. Present├│ el acto Jes├║s Com├¡n, dando paso al diputado en Cortes, Jos├® Lamami├® de Clairac, terrateniente salmantino, cat├│lico, carlista, y tradicionalista de derechas, que se├▒al├│ que la soluci├│n ├║nica a los problemas estaba en la doctrina cat├│lica. Habl├│ despu├®s M┬¬ Rosa Urraca, se├▒orita que apunt├│ que la obra para erradicar la amenaza revolucionaria, estaba ya en marcha. Finalmente, Esteban Bilbao record├│ los tres principios de la Espa├▒a tradicional: el altar (dios), la bandera (patria), y el Trono (rey). A la salida del mitin, se produjeron disturbios resultando 13 heridos de diversa consideraci├│n, y varios detenidos. En la imagen, la calle de Albareda con tradicionalistas filas para acceder al nov├¡simo front├│n Aragones. Al fondo, el paseo de la Independencia. A la izquierda, los muros del Gobierno Militar, antiguo convento de las Carmelitas Descalzas de San Jos├®. Fuente visual: Foto Mart├¡nez, "Mundo Gr├ífico".', 1933, 1933, 1933, 'Anos 30', 'CENTRO', 41.64949800, -0.88518200, '0101000020E61000007D40A0336953ECBFA1681EC022D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21327145723.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21327145723.webp', 'https://www.flickr.com/photos/zaragozaantigua/21327145723/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21860, 'Pl. de Arag├│n 1933', 'Imagen capturada en la arbolada plaza de Arag├│n y centrada en el ambulante ciclista-afilador Soriano, pionero emprendedor del maridaje entre el moderno deporte del ciclismo y el antiguo oficio del vaciado de navajas, cuchillos y tijeras. La bicicleta permite transportar las piedras de amolar y derivar, sin excesivo esfuerzo, la fuerza motriz que requiere el giro en altura (sin rozamiento con el suelo) de la rueda trasera. La sencillez del proceso era inversamente proporcional al eco y expectaci├│n que despertaba a su paso, de forma especial cuando era llamado para un servicio y paraba a realizarlo de forma inmediata en la misma calle o plaza en que se encontrara. De forma autom├ítica, como por ensalmo, y sin necesidad de convocatoria previa, una nutrida parroquia se congregaba para asistir al evento gratis et amore. Hoy en d├¡a, muy ocasionalmente, es posible ver en la ciudad alg├║n afilador que se anuncia con su caracter├¡stico chiflo o peque├▒a flautilla. Este sonido, cuando consigue dejarse o├¡r entre el estr├®pito del urbano tr├ínsito motorizado, mantiene un at├ívico efecto de llamada y atracci├│n irresistible e incomprensible para el postmoderno, o postmoderna. Fuente visual: www.mecd.gob.es/.', 1933, 1933, 1933, 'Anos 30', 'CENTRO', 41.64838600, -0.88523500, '0101000020E610000032C9C859D853ECBF9697FC4FFED24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/36262596111.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/36262596111.webp', 'https://www.flickr.com/photos/zaragozaantigua/36262596111/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21976, 'Plaza Arag├│n 1944', 'Proyecto no realizado para la ├║ltima reforma integral del hotelito del n├║mero 12 de la plaza de Arag├│n, que fue ampliando su tama├▒o de 1868 a 1944, qued├índose sin las dos filas laterales previstas en el dibujo, aunque s├¡ elevando su altura como se mostraba. Hoy es el ├║nico edificio primigenio conservado, y alberga un restaurante de lujo. Fuente: Estudio Coyne. DARA/AHPZ.', 1944, 1944, 1944, 'Anos 40', 'CENTRO', 41.64900000, -0.88511900, '0101000020E6100000E42EC214E552ECBF508D976E12D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24914495539.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24914495539.webp', 'https://www.flickr.com/photos/zaragozaantigua/24914495539/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24745, 'Calle del Sobrarbe 1891', 'Aspecto de la calle del Sobrarbe, con la iglesia de N┬¬ S┬¬ de Altab├ís en construcci├│n, inaugurada un a├▒o despu├®s.', 1891, 1891, 1891, 'Siglo XIX', 'CASCO HIST├ôRICO', 41.65822000, -0.87480700, '0101000020E6100000DBFAE93F6BFEEBBF5CC98E8D40D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15674320287.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15674320287.webp', 'https://www.flickr.com/photos/zaragozaantigua/15674320287/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21981, 'Pl. de Basilio Para├¡so c.1942', 'Vista editada como postal por Garc├¡a Garrabella. La panor├ímica, con la plaza de Para├¡so a los pies, se hizo en altura desde la cima del (edificio) El├¡seos, erigido en el arranque del paseo del general Mola. Un poco m├ís al frente, la plaza de Arag├│n y el entronque con la arboleda del paseo de la Independencia. Hacia la derecha, el paseo de Marina Moreno. Hacia la izquierda, el paseo de Pamplona. En la plaza de Para├¡so estaba empadronado el primaporte├▒o c├®sar donado por Mussolini, aunque ya en "modo espera", pendiente de una reubicaci├│n m├ís imperial en la zona de la muralla de piedra, romana e isl├ímica, junto al alc├ízar de la Sudda. Da la sensaci├│n de que la instalaci├│n de la preciosa fuente luminosa, amable y desinteresadamente donada en la siguiente d├®cada, supuso que antes hubiera que hacerse una apreciable escarda de ├írboles que despejara la visual para el tr├ífico motorizado. Para ├írboles, ya estaba el parque Primo de Rivera, y lo primero, es lo primero. Al fondo, la ciudad. Fuente: www.todocoleccion.net/', 1942, 1942, 1942, 'Anos 40', 'CENTRO', 41.64849400, -0.88480900, '0101000020E61000005A9BC6F65A50ECBF7CD3F4D901D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/25572979586.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/25572979586.webp', 'https://www.flickr.com/photos/zaragozaantigua/25572979586/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21988, 'Plaza de Arag├│n 1949', 'Imagen de la antigua plaza de Arag├│n como espacio donde poder disfrutar del sol de invierno, apreciado por la chiquiller├¡a como si de un parque se tratara. Al fondo, a la izquierda, la casa de Luis P├®rez Cistu├® que unos a├▒os antes hab├¡a sido muy reformada, y recrecida en vertical. Al fondo, y a la derecha, las solaneras de las desaparecidas casonas recayentes a la calle Albareda. Fuente visual: Gerardo Sancho Ramo, AMZ.', 1949, 1949, 1949, 'Anos 40', 'CENTRO', 41.64873900, -0.88487000, '0101000020E6100000C6C4E6E3DA50ECBFE3512AE109D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30287910596.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30287910596.webp', 'https://www.flickr.com/photos/zaragozaantigua/30287910596/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22019, 'Los sombr├¡os a├▒os 40', 'El jueves 27 de febrero (festividad de San Gabriel de la Dolorosa) del a├▒o en curso 2020, a las 19 horas y en la sala Pilar Sinu├®s del Edificio Paraninfo de la Universidad de Zaragoza (plaza de Basilio Para├¡so n┬║ 4), tendr├í lugar el acto de presentaci├│n del libro "Memoria visual de Zaragoza. Los sombr├¡os a├▒os 40", editado por El Peri├│dico de Arag├│n. Entrada libre hasta completar aforo. Abstenerse desaforados (en su primera acepci├│n). El acto contar├í con la presencia de Nicol├ís Espada, director de El Peri├│dico de Arag├│n, y de los autores del libro, Jos├® Mar├¡a Ballest├¡n Miguel y Antonio Tausiet, del Gran Archivo Zaragoza Antigua (GAZA). Previsiblemente, no contaremos con presencia de concejales de aquellos a├▒os, ni de estos actuales. En la imagen, portada del libro, aspecto en altura de la antigua plaza de Arag├│n de toda la vida. Foto Estudio Coyne (AHPZ), coloreada de forma in├®dita para la ocasi├│n.', 1940, 1940, 1949, 'Anos 40', 'CENTRO', 41.64843900, -0.88493500, '0101000020E61000008CBE82346351ECBFB939950C00D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/49557421926.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/49557421926.webp', 'https://www.flickr.com/photos/zaragozaantigua/49557421926/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25606, 'Condes de Arag├│n 1973', 'Cosecha en el Pol├¡gono Gran V├¡a. La progresiva urbanizaci├│n de este entorno supuso la apertura de nuevos viales, algunos de ellos fronteros con una periferia agr├¡cola productiva desde siglos antes, en el m├ís antiguo t├®rmino de Romareda, desde el siglo XII, y el t├®rmino de Almotilla, desde el siglo XIV. En la imagen, cosechadora francesa Braud 405 en plena faena en un campo de cereal con el fondo edilicio del n┬║ 23 de la calle de los Condes de Arag├│n, casi terminado, al igual que su vecino del n┬║ 26-C de la calle de As├¡n y Palacios, a la izquierda.', 1973, 1973, 1973, 'Anos 70', 'UNIVERSIDAD', 41.63742400, -0.90727300, '0101000020E6100000E066F1626108EDBFBFD7101C97D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/16225764972.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/16225764972.webp', 'https://www.flickr.com/photos/zaragozaantigua/16225764972/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22246, 'Calle del General Sanjurjo c.1956', 'Imagen capturada en el interior de la iglesia del Carmen Calzado o de los carmelitas Calzados sita en el n├║mero 7 de la calle del General Sanjurjo. El espl├®ndido y gran convento carmelita Calzado del Carmen qued├│ arruinado tras los episodios b├®licos de 1808-1813, aunque luego se reconstruyeron la iglesia, convento y colegio de San Jos├® con su iglesia. En 1836 el conjunto fue desamortizado y, al no encontrar postor, qued├│ en manos p├║blicas, cediendo parte de sus instalaciones para cuartel del ramo de la Guerra, inclusa de ni├▒os exp├│sitos, casa de monta, escuela de Veterinaria, cuartel de la Guardia Civil y dep├│sito de cad├íveres. En 1938 la iglesia fue habilitada por los nacionalistas, a trav├®s del Servicio de Defensa del Patrimonio Art├¡stico Nacional, como almac├®n o dep├│sito provisional de obras art├¡sticas religiosas "abandonadas por la rapi├▒a roja en su huida" (sic). En 1948 los carmelitas calzados volvieron a ocupar la antigua Iglesia del noviciado, dot├índola de culto, que fue bendecida e inaugurada por el arzobispo Rigoberto Domenech Valls, convirti├®ndose en templo muy frecuentado. A├▒os despu├®s comenzaron las obras del proyectado ensanchamiento de la calle del General Sanjurjo para convertirla en parte de la nueva V├¡a Imperial. De esta forma, en 1964 esta iglesia fue definitivamente derribada.', 1956, 1956, 1956, 'Anos 50', 'CENTRO', 41.65037200, -0.88666300, '0101000020E61000000C5872158B5FECBFF71DC3633FD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51710073433.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51710073433.webp', 'https://www.flickr.com/photos/zaragozaantigua/51710073433/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22254, 'Plaza de Arag├│n 1966', 'Ayuntamiento de Zaragoza/Gerardo Sancho Ramo/1966. El Real Zaragoza se jugaba los octavos de final de la "Copa de Ferias" con el escoc├®s equipo del Heart of Midlothian, y la eliminatoria era a dos partidos (ida, y vuelta). En ambos encuentros terminaron empatados, y las normas dec├¡an que para desempatar era preciso un tercer encuentro, en Zaragoza. En la imagen, la plantilla del equipo escoc├®s, de civil, visitando la ciudad, y hay que agradecerles el buen gusto del posado de la imagen, precisamente en la Plaza de Arag├│n, para as├¡ tener una buena panor├ímica de los edificios del fondo, en el lado de los n├║meros 9 a 13. De izquierda a derecha, la base del monumento a Juan de Lanuza, y un pedazo del n┬║ 9, la entonces Capitan├¡a General de la V┬¬ Regi├│n Militar, construida en 1893, y que perdura, aunque ya no como Capitan├¡a General. Luego, el n┬║ 10, esquina con calle Canfranc, desaparecido. Sigue un pedazo del n┬║ 11, en la otra esquina con la calle Canfranc, desaparecido. Por supuesto que el f├║tbol es interesante.', 1966, 1966, 1966, 'Anos 60', 'CENTRO', 41.64840000, -0.88479600, '0101000020E6100000333674B33F50ECBFFB5C6DC5FED24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14664561560.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14664561560.webp', 'https://www.flickr.com/photos/zaragozaantigua/14664561560/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25628, 'Paseo isabel la Cat├│lica 2009', 'Foto: Oliver Duch. Vista del paseo de Isabel la Cat├│lica, tomada con motivo del inicio de las obras de la l├¡nea 1 del tranv├¡a, el lunes 21 de septiembre de 2009. Centra la imagen el edificio de la central tecnol├│gica de la Caja de Ahorros de la Inmaculada, obra de Jos├® Manuel P├®rez Latorre. La toma se extiende hacia el norte, permitiendo contemplar la c├║pula de la iglesia de Santiago, la chimenea y la contaminaci├│n de Saica, en el Picarral, el Pilar y las chimeneas de la azucarera del Arrabal. Fuente: Heraldo de Arag├│n.', 2009, 2009, 2009, 'Siglo XXI', 'UNIVERSIDAD', 41.63690300, -0.89922600, '0101000020E61000000BD0B69A75C6ECBFB5DC990986D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33069676702.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33069676702.webp', 'https://www.flickr.com/photos/zaragozaantigua/33069676702/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22255, 'Plaza de Arag├│n 1966', 'Ayuntamiento de Zaragoza/Gerardo Sancho Ramo/1966. El Real Zaragoza se jugaba los octavos de final de la "Copa de Ferias" con el escoc├®s equipo del Heart of Midlothian, y la eliminatoria era a dos partidos (ida, y vuelta). En ambos encuentros terminaron empatados, y las normas dec├¡an que para desempatar era preciso un tercer encuentro, en Zaragoza. En la imagen, la plantilla del equipo escoc├®s, de civil, visitando la ciudad, y hay que agradecerles el buen gusto del posado de la imagen, precisamente en la Plaza de Arag├│n, para as├¡ tener una buena panor├ímica de los edificios del fondo, en el lado de los n├║meros 9 a 13. En la imagen, un pedazo del n┬║ 11, desaparecido luego. Sigue el n┬║ 12, construido en 1888, que perdura. Finalmente, el n┬║ 13, esquina con Albareda, desaparecido. Entre el 11 y el 13 vemos las traseras del n┬║ 5 de la calle Ponzano, hoy ocultas por la mole del nuevo n┬║ 13 de la Plaza de Arag├│n. Por supuesto que el f├║tbol es interesante.', 1966, 1966, 1966, 'Anos 60', 'CENTRO', 41.64836800, -0.88475300, '0101000020E610000061360186E54FECBFEFE2FDB8FDD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14664737017.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14664737017.webp', 'https://www.flickr.com/photos/zaragozaantigua/14664737017/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22275, 'Puerta del Carmen 1968', 'Ayuntamiento de Zaragoza. Gerardo Sancho Ramo. 18/05/1968. "Vista de la calle Cesar Augusto en obras." Al fondo, la Puerta del Carmen va a quedar bien despejada de edificios, ├írboles, y cosas para que la V├¡a Imperial llegue desde el Ebro. Los modestos edificios de la izquierda ilustran lo limitados de miras que eran nuestros ancestros, que en lugar de avenidas, hac├¡an calles, y en lugar de bloques, parcelas. Afortunadamente, el progreso estaba llegando para poner a cada uno en su sitio, y a los coches, en todas partes.', 1968, 1968, 1968, 'Anos 60', 'CENTRO', 41.65103800, -0.88619100, '0101000020E61000001E4E603AAD5BECBF043A933655D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14962135362.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14962135362.webp', 'https://www.flickr.com/photos/zaragozaantigua/14962135362/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22481, 'P.┬║ de Pamplona 1967', 'Imagen capturada en arranque del paseo de Pamplona durante el paso de la banda de m├║sica de la 8.┬¬ Divisi├│n de Infanter├¡a del ej├®rcito de los Estados Unidos de Am├®rica del Norte con motivo de su participaci├│n de las Fiestas de Primavera, tambi├®n denominadas Coso Blanco, de ese a├▒o. Al fondo, a la izquierda, despunta la torre de la iglesia de la Madre del Salvador de los PP. Jesuitas. En el centro, el colegio del Sagrado Coraz├│n y la gran mole del edificio El├¡seos rematado con su publicitaria peineta. A la derecha, la facultad de Medicina y Ciencias de la Universidad y el comienzo de los n├║meros impares del paseo, con interesante vista del antiguo n┬║ 5. Fuente visual: Jarke/Jaria, AMZ.', 1967, 1967, 1967, 'Anos 60', 'CENTRO', 41.64831400, -0.88668300, '0101000020E6100000D369DD06B55FECBFFCC401F4FBD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/38521374621.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/38521374621.webp', 'https://www.flickr.com/photos/zaragozaantigua/38521374621/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22535, 'Plaza del Carmen 1970', 'Captura de la calle de la Vieja Guardia, la plaza de N┬¬ S┬¬ del Carmen (izquierda), y la calle de Casa Jim├®nez (al fondo). Antes, esta calle formaba parte de la calle Casa Jim├®nez, pero en 1943 el ayuntamiento decidi├│ rendir homenaje a los falangistas de camisa vieja, y ponerle ese nombre a este tramo. Ya antes, tras el 18 de julio de 1936, los mun├¡cipes fascistas piquetearon el nombre de la "Plaza del Pueblo", y le devolvieron el m├ís antiguo de "Plaza del Carmen". Desde 1979, recuperada la democracia municipal, a esta calle se la denomina Marceliano Is├íbal. La del Carmen sigue siendo la del Carmen. La imagen ilustra la tipolog├¡a de viviendas que caracterizaban esta parte de la ciudad desde el siglo XVIII: 2, 3, 4 alturas m├íximo, m├ís los bajos. Al fondo, el antiguo Convento de las Carmelitas Descalzas de San Jos├®, all├¡ ubicado desde el siglo XVII, convertido luego en sede del Gobierno Militar. Tras la Operaci├│n Cuarteles, se baraj├│ la posibilidad de derribar todas las instalaciones, pero una cata arqueol├│gica posibilit├│ que el espacio fuera reconvertido en municipal centro administrativo que incluye, mejor visible desde la calle Ponzano, la antigua iglesia conventual, cerrada, sin restaurar, y pr├ícticamente desconocida. En la esquina de la plaza con la calle, en el centro de la imagen, un bar que hoy es un caf├® con el mismo nombre insular. Encima, ni m├ís ni menos que la joya de la antigua casa del siglo XVII de don Eugenio Samper, vecina del Convento de las Recogidas, profundamente remodelada en el XVIII cuando su propietario era don Francisco Montemayor, y que a finales de siglo fuera de Pedro Cort├®s y Larraz, Obispo de Guatemala, y luego de Tortosa. Es por eso a esta casa desde entonces se le conoc├¡a como "del Obispo". Esta interesante historia no import├│ mucho a los propietarios que la piquetearon, junto con todo el conjunto de los otros edificios, para construir la cosa que hoy hay.', 1970, 1970, 1970, 'Anos 70', 'CENTRO', 41.65076500, -0.88472600, '0101000020E6100000FB777DE6AC4FECBFD3307C444CD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14849454451.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14849454451.webp', 'https://www.flickr.com/photos/zaragozaantigua/14849454451/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22538, 'Plaza de Arag├│n 1972', 'Troleb├║s de la l├¡nea "Ciudad Jard├¡n" en la Plaza de Arag├│n, yendo hacia la Terminal de la L├¡nea, situada en la Plaza de Santa Engracia. Esta l├¡nea fue clausurada en octubre de 1975. Fuente visual: www.flickr.com/photos/jhm0284/5812542337/in/photostream/', 1972, 1972, 1972, 'Anos 70', 'CENTRO', 41.64825600, -0.88471500, '0101000020E610000001FBE8D4954FECBFC8B7770DFAD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14868792646.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14868792646.webp', 'https://www.flickr.com/photos/zaragozaantigua/14868792646/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22593, 'Plaza de Arag├│n 1972', 'Un 200 de la l├¡nea 11 en la plaza de Arag├│n, camino de Parque. Al fondo, por encima del edificio de Capitan├¡a, el moderno remate del chafl├ín entre paseo Pamplona-Doctor Cerrada, empleado como atalaya publicitaria de ingenios electr├│nicos. Justo detr├ís del tranv├¡a, interesante visual del antiguo hotelito del n┬║ 10 de la plaza, en su segunda versi├│n formal, entre Capitan├¡a y Canfranc. A su derecha, ca├▒izos de obra que anuncian erecci├│n de nuevo edificio torril despersonalizado sobre el solar del ya piqueteado hotelito n┬║ 11 de la plaza. Fuente visual: www.flickr.com/photos/jhm0284/5813112116/in/photostream/', 1972, 1972, 1972, 'Anos 70', 'CENTRO', 41.64856000, -0.88505300, '0101000020E6100000074147AB5A52ECBF34BF9A0304D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/16674031758.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/16674031758.webp', 'https://www.flickr.com/photos/zaragozaantigua/16674031758/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22621, 'P.┬║ de Pamplona 1977', 'Inmueble esquinero entre el paseo de Pamplona y la calle de Bilbao, proyectado por Julio Bravo Folch a comienzos del siglo XX, cerca de la Escuela de Comercio y el convento-colegio de las Esclavas del Sagrado Coraz├│n de Jes├║s. Al poco tiempo se le anex├│ un nuevo edificio de viviendas de alquiler, a la derecha de la imagen, dise├▒ado por Marcelino Secorum. M├ís tarde, a la Escuela le sucedi├│ un nuevo bloque en los a├▒os 50, y las Esclavas se trasladaron a finales de los a├▒os 60. Este edificio, y su anexo de la derecha, fueron objeto de una transformaci├│n a la zaragozana en los a├▒os 80.', 1977, 1977, 1977, 'Anos 70', 'CENTRO', 41.64848000, -0.88639400, '0101000020E610000027DC2BF3565DECBF170E846401D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19776210025.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19776210025.webp', 'https://www.flickr.com/photos/zaragozaantigua/19776210025/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22671, 'Plaza de Arag├│n 1970', 'La metamorfosis del paseo de la Independencia, tras su imposici├│n como autopista, impuls├│ por simpat├¡a la mudanza de algunos edificios que la flanqueaban, desde la plaza de Espa├▒a, hasta la plaza de Para├¡so. As├¡, la plaza de Arag├│n comenz├│ a padecer su particular "transici├│n" edilicia, que en la imagen queda dram├íticamente constrastada entre los luminosos, modernos y atractivos bloques, y las oscuras, viejas y tenebrosas casonas que afeaban el entorno, y bien poco ayudaban a la imagen de una ciudad como la nueva Zaragoza del milagro (econ├│mico). Esta falla ser├¡a enmendada, pr├ícticamente, en la d├®cada siguiente. Fuente visual: Gerardo Sancho Ramo (Archivo P├║blico Municipal).', 1970, 1970, 1970, 'Anos 70', 'CENTRO', 41.64841500, -0.88489300, '0101000020E6100000D1B2EE1F0B51ECBF309E4143FFD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24119327112.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24119327112.webp', 'https://www.flickr.com/photos/zaragozaantigua/24119327112/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22735, 'Plaza Arag├│n 1972', 'Confluencia de varios medios de transporte en la plaza de Arag├│n, con el edificio de Capitan├¡a al fondo a la derecha. A la izquierda, la unidad 55 de la l├¡nea de troleb├║s "Ciudad Jard├¡n" se dirige a su parada en la plaza de Santa Engracia. A la derecha, un taxi de la flota local. Fuente: Colecci├│n Daniel Andr├®s.', 1972, 1972, 1972, 'Anos 70', 'CENTRO', 41.64834900, -0.88470100, '0101000020E6100000C2A1B778784FECBF79B29B19FDD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31260366451.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31260366451.webp', 'https://www.flickr.com/photos/zaragozaantigua/31260366451/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24841, 'Miralbueno 1951', 'Vivienda unifamiliar en la huerta del barrio de Miralbueno, hoy desaparecida. Fuente; Colecci├│n particular.', 1951, 1951, 1951, 'Anos 50', 'MIRALBUENO', 41.65696500, -0.94504700, '0101000020E61000006ADAC534D33DEEBFEECEDA6D17D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32843646510.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32843646510.webp', 'https://www.flickr.com/photos/zaragozaantigua/32843646510/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22739, 'Plaza de Arag├│n 1977', 'Imagen centrada en la cobertura de obra reci├®n instalada sobre el edificio del antiguo n┬║ 10 de la plaza de Arag├│n, en proceso de homologarse a su vecino del n┬║ 11, al otro lado de la calle de Canfranc, ya procesado unos pocos a├▒os antes. A su izquierda, el edificio de Capitan├¡a. Fuente visual: Gerardo Sancho Ramo, AMZ.', 1977, 1977, 1977, 'Anos 70', 'CENTRO', 41.64855400, -0.88536300, '0101000020E610000091D442C9E454ECBF51D845D103D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31563726650.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31563726650.webp', 'https://www.flickr.com/photos/zaragozaantigua/31563726650/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22744, 'P.┬║ de Pamplona 1970', 'Imagen posiblemente capturada en el desfile de carrozas art├¡sticas del denominado "Coso Blanco", durante las Fiestas de la Primavera de ese a├▒o. La desbordante alegr├¡a del p├║blico contagia a las muchachas ataviadas con vestidos neoregionalistas, en un escenario plagado de barrocas y seriadas representaciones del f├®lido icono de la ciudad, delante de la antigua fachada del n┬║ 2 del paseo, chaflanero con la calle de Bilbao. Fuente visual: foto Gerardo Sancho Ramo, AMZ.', 1970, 1970, 1970, 'Anos 70', 'CENTRO', 41.64854600, -0.88647900, '0101000020E6100000B4E73235095EECBFCFF9298E03D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32192727064.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32192727064.webp', 'https://www.flickr.com/photos/zaragozaantigua/32192727064/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22855, 'Gr├║a municipal 1983', 'Una mula, que al parecer impide el eficaz desenvolvimiento del tr├ífico rodado, es retirada por la gr├║a municipal para llevarla a los dep├│sitos de veh├¡culos requisados. La escena se produce en pleno centro de la ciudad, en la plaza de Arag├│n. El servicio de gr├║as de la polic├¡a municipal, luego local, fue aumentado hasta las 10 unidades al a├▒o siguiente. Ya en 1990, entr├│ en funcionamiento el nuevo dep├│sito de veh├¡culos en la carretera de Castell├│n, adem├ís de las nuevas instalaciones de caballer├¡a. Por fin, en 1995, el servicio fue privatizado, acabando por convertir a Zaragoza en la ciudad espa├▒ola con la tasa m├ís alta de devoluci├│n de veh├¡culos. A la izquierda, marquesina con publicidad de una omnipresente entidad de ahorro local, que pronto cambiar├¡a de imagen corporativa. A la derecha, sobre el adoquinado firme por donde circularan tranv├¡as, un autob├║s urbano.', 1983, 1983, 1983, 'Anos 80', 'CENTRO', 41.64855100, -0.88471200, '0101000020E6100000BD1E4C8A8F4FECBFE0641BB803D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15523578107.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15523578107.webp', 'https://www.flickr.com/photos/zaragozaantigua/15523578107/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23051, 'Vista 1992', 'Imagen capturada desde la altura del Edificio El├¡seos con una vista que desde la moderna fuente cibern├®tica de la plaza de Basilio Para├¡so, en primer t├®rmino, y pasando por la plaza de Arag├│n y el paseo de la Independencia, alcanza hasta la plaza de Espa├▒a, al fondo. Esta zona segu├¡a siendo una gran cicatriz automovil├¡stica abierta en el coraz├│n del centro urbano, mientras el Plan de Tr├ífico vigente planteaba en t├®rminos de "inundaci├│n" y "congesti├│n" la situaci├│n de la movilidad en Zaragoza. Todav├¡a era tiempo de soluciones m├ís cosm├®ticas que efectivas.', 1992, 1992, 1992, 'Anos 90', 'CENTRO', 41.64851200, -0.88502100, '0101000020E61000002FBE688F1752ECBF2288F37002D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50443752333.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50443752333.webp', 'https://www.flickr.com/photos/zaragozaantigua/50443752333/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23267, 'Torre del Pino 1808', '"Alarma en la Torre del Pino. En donde se distinguieron los Patriotas rechazando a los Franceses el d├¡a 4 de Agosto de 1808: en este encuentro muri├│ el comandante de armas D. Antonio Cuadros". Serie Ruinas de Zaragoza, de Juan G├ílvez (dibujo) y Fernando Brambila (grabado), C├ídiz, 1812. Esta estampa representa la acci├│n del 4 de agosto de 1808 en la denominada Torre del Pino, propiedad de las carmelitas descalzas de San Jos├®, en lo que m├ís tarde ser├¡a el Gobierno Militar en la calle del Marqu├®s de Casa-Jim├®nez (espacio que limitan actualmente esta calle y las de Bilbao, Ponzano, Canfranc). La c├║pula con dos peque├▒as torres del fondo es la iglesia de San Fernando. Fuente visual: bvpb.mcu.es/', 1808, 1808, 1808, 'Siglo XIX', 'CENTRO', 41.64908600, -0.88549700, '0101000020E61000007898F6CDFD55ECBF4E25034015D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15080226208.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15080226208.webp', 'https://www.flickr.com/photos/zaragozaantigua/15080226208/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23645, 'Capitan├¡a General c.1908', 'AHPZ. Estudio Coyne. Ca. 1908 "Capitan├¡a General."', 1908, 1908, 1908, 'Anos 1900', 'CENTRO', 41.64816800, -0.88569700, '0101000020E61000003C4A253CA157ECBF2828452BF7D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15822955885.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15822955885.webp', 'https://www.flickr.com/photos/zaragozaantigua/15822955885/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23646, 'Capitan├¡a General c.1908', 'Lucien L├®vy. c.1908. "La Capitan├¡a General".', 1908, 1908, 1908, 'Anos 1900', 'CENTRO', 41.64816800, -0.88569700, '0101000020E61000003C4A253CA157ECBF2828452BF7D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15903746606.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15903746606.webp', 'https://www.flickr.com/photos/zaragozaantigua/15903746606/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23648, 'Calle Soberan├¡a Nacional 1920', 'Imagen, a la izquierda, de la monumental fachada principal del Cuartel de Artiller├¡a de El Carmen, en la calle de la Soberan├¡a Nacional. Su denominaci├│n proven├¡a del antiguo convento del Carmen de los PP. Carmelitas Calzados. Por aqu├¡ pasa en doble v├¡a la L├¡nea de Madrid del tranv├¡a, que une la plaza de la Constituci├│n con la Estaci├│n de Madrid. En este Cuartel se produjo, en enero de 1920, una sublevaci├│n interna enmarcada en los graves conflictos sociales de la ├®poca, y que termin├│ con la muerte de diez personas, tres durante los hechos, y siete fusilados despu├®s. Tuvo enorme resonancia incluso en medios de informaci├│n de car├ícter estatal, y fue convenientemente instrumentalizado para justificar el posterior golpe de estado de Primo de Rivera (con la anuencia del rey), entre cuyos objetivos estaba "restablecer la paz social". En la imagen, la calle Soberan├¡a Nacional continuaba, al fondo y hacia la izquierda, hasta llegar a la Puerta del Carmen. La fotograf├¡a se ha tomado desde la Plaza del Pueblo. Fuente visual: Fotos Alonso, Revista Nuevo Mundo', 1920, 1920, 1920, 'Anos 20', 'CENTRO', 41.65099800, -0.88467800, '0101000020E6100000B7B3AF3C484FECBF76E107E753D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19126035736.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19126035736.webp', 'https://www.flickr.com/photos/zaragozaantigua/19126035736/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23658, 'Cuartel del Carmen c.1955', 'Imagen en altura desde el n┬║ 2 de la calle Capit├ín Portol├®s (antigua de Soberan├¡a Nacional) del Cuartel del Carmen recayente a dicha calle, y a la calle de la Vieja Guardia (antes integrante de la calle Casa Jim├®nez), a la izquierda, que desemboca en el edificio del Gobierno Militar, que fuera antiguo convento de las Carmelitas Descalzas de San Jos├®. Al fondo, destaca en altura el gran Front├│n Aragon├®s de la calle Albareda y, a la derecha, el reciente bloque del final de la calle Canfranc. Otro entra├▒able recuerdo de que en Zaragoza muchos nombres de sus viales son una interesante ant├¡tesis de las cosas que son as├¡ "de toda la vida". Este Cuartel del Carmen fue desmantelado tiempo despu├®s, y vendido su solar. Parte del dinero conseguido fue utilizado para la construcci├│n del nuevo Hospital Militar, en Casablanca. Fuente visual: Gerardo Sancho Ramo, AMZ.', 1955, 1955, 1955, 'Anos 50', 'CENTRO', 41.65087900, -0.88485900, '0101000020E6100000CB4752D2C350ECBF9C53C90050D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22943862904.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22943862904.webp', 'https://www.flickr.com/photos/zaragozaantigua/22943862904/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23669, 'Plaza de Arag├│n 1982', 'Candidatos sobre las vallas de obra que delimitan el solar donde estuviera el hotelito del n┬║ 10 de la plaza de Arag├│n, dise├▒ado por Fernando de Yarza con aportaciones t├®cnicas de Ricardo Magdalena, construido en 1887 y reformado luego. Casi un siglo despu├®s, este espacio ser├¡a contenedor de otra muestra de la flamante y descontextualizada arquitectura moderna que caracteriza la plaza. A la izquierda, el edificio de la Capitan├¡a General y a la derecha el inmueble del n┬║ 16 de la calle de Ponciano Ponzano. En primer t├®rmino cohabitan carteles publicitarios que hacen alusi├│n a la campa├▒a electoral de las elecciones generales de octubre de ese a├▒o. Entre ellos, el de la candidatura encabezada por Manuel Fraga Iribarne de la coalici├│n formada por Alianza Popular, Partido Dem├│crata Popular, y partidos regionalistas de derecha, como el PAR; y el de la candidatura encabezada por Felipe Gonz├ílez M├írquez, del PSOE. Fuente visual: foto Gerardo Sancho Ramo, AMZ.', 1982, 1982, 1982, 'Anos 80', 'CENTRO', 41.64855400, -0.88536300, '0101000020E610000091D442C9E454ECBF51D845D103D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31969575076.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31969575076.webp', 'https://www.flickr.com/photos/zaragozaantigua/31969575076/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23673, 'Cuartel del Carmen 1920', 'Imagen del patio del cuartel de artiller├¡a del Carmen, escenario de un invernal intento de sublevaci├│n armada protagonizado por media docena de soldados, que termin├│ en fracaso. Tras los arcones de municiones de primer plano, y al fondo, fueron fusilados los voluntaristas rebeldes de acuerdo con el C├│digo de Justicia Militar vigente. En el pabell├│n de la derecha estaba el ingreso principal al cuartel, desde la calle de la Soberan├¡a Nacional. Las traseras del de la izquierda limitaban con el edificio de la Escuela de Veterinaria, recayente a esa misma calle, frente al convento de la Encarnaci├│n. Fuente visual: foto Alonso, en Mundo Gr├ífico.', 1920, 1920, 1920, 'Anos 20', 'CENTRO', 41.65083900, -0.88526700, '0101000020E61000000A4CA7751B54ECBF0DFB3DB14ED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33473608256.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33473608256.webp', 'https://www.flickr.com/photos/zaragozaantigua/33473608256/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23676, 'Soberan├¡a Nacional 1933', 'Imagen de la calle de la Soberan├¡a Nacional con una buena perspectiva del enorme cuartel de artiller├¡a del Carmen. La captura se ha realizado desde el final de la calle de Ram├│n y Cajal, hacia donde se dirige por la izquierda el tendido tranviario de la l├¡nea de Madrid. Al fondo, la plaza del Pueblo. En la esquina del muro cuartelario quedan huellas de la l├ípida que durante la dictadura de Primo de Rivera (1926) escenific├│ el cambio de denominaci├│n de la calle por la de General Sanjurjo. La llegada de la democracia durante la Segunda Rep├║blica supuso la reposici├│n del nombre del vial, hasta que la soberan├¡a nacional fue violentada por las armas facciosas tras el 18 de julio de 1936. A la derecha de la imagen, fuera de plano, y en direcci├│n a la Puerta del Carmen se ubicaba la antigua casa-cuartel de la Guardia civil, y el ruinoso inmueble de la Escuela Superior de Veterinaria. Fuente visual: www.mecd.gob.es/.', 1933, 1933, 1933, 'Anos 30', 'CENTRO', 41.65097600, -0.88597500, '0101000020E6100000EE5A423EE859ECBF8E3D7B2E53D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/36673668205.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/36673668205.webp', 'https://www.flickr.com/photos/zaragozaantigua/36673668205/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23688, 'Plaza de Arag├│n, 1936', 'El general Mill├ín Astray durante su estancia en Zaragoza el 26 de agosto programada dentro de una ronda de visitas de altos jerarcas golpistas a las principales ciudades donde hab├¡a triunfado la sublevaci├│n armada contra la democracia republicana. En la imagen in├®dita este general sale en coche de la sede de la 5┬¬ Divisi├│n Org├ínica sita en el n┬║ 9 de la plaza de Arag├│n para dirigirse al cuartel de caballer├¡a de Castillejos donde inspeccionar las fuerzas de caballer├¡a y milicias de Falange.', 1936, 1936, 1936, 'Anos 30', 'CENTRO', 41.64820800, -0.88568600, '0101000020E610000042CD902A8A57ECBFB680D07AF8D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51164511510.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51164511510.webp', 'https://www.flickr.com/photos/zaragozaantigua/51164511510/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24135, 'Sal├│n de Pignatelli 1875', '"Plano de los solares en venta procedentes de la Exposici├│n Aragonesa y terrenos adyacentes, en Zaragoza", Segundo D├¡az, 1875. Planta del entorno de la actual plaza de Arag├│n, con la planificaci├│n de su desarrollo urban├¡stico tras la Exposici├│n Aragonesa de 1868 en esa ubicaci├│n. Incluye superficie y precio de cada nuevo solar. Fuente: AMZ.', 1875, 1875, 1875, 'Siglo XIX', 'CENTRO', 41.64836500, -0.88495900, '0101000020E6100000AEA069899551ECBF7E6FD39FFDD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19367940539.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19367940539.webp', 'https://www.flickr.com/photos/zaragozaantigua/19367940539/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24433, 'Ruinas de la iglesia del Carmen 1808', 'Imagen de la aguada sobre papel verjurado realizada en 1812 y que representa las ruinas del interior de la iglesia del convento de Nuestra Se├▒ora del Carmen, en este caso en una vista desde el sotocoro hacia el lado de la Ep├¡stola, que fue considerada una de las ruinas m├ís emblem├íticas producidas como consecuencia del primero de los dos asedios franceses de la ciudad en 1808-1809, que supuso la ruina de la gran iglesia de este convento barroco.', 1808, 1808, 1808, 'Siglo XIX', 'CENTRO', 41.65076500, -0.88521400, '0101000020E610000054C37E4FAC53ECBFD3307C444CD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/54386789164.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/54386789164.webp', 'https://www.flickr.com/photos/zaragozaantigua/54386789164/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24868, 'Plaza de Arag├│n 1974', 'In├®dita imagen capturada en la plaza de Arag├│n y centrada en uno de los modernos "postes de parada" reci├®n instalados por la empresa Los Tranv├¡as de Zaragoza, S.A. en las paradas m├ís c├®ntricas de los autobuses urbanos, como esta. El elemento m├ís novedoso radicaba en la informaci├│n que proporcionaba sobre la l├¡nea o l├¡neas que all├¡ paraban, y los itinerarios que realizaban. En este caso, este poste indicaba la parada de las l├¡neas 21 (Plaza del Pilar-Barrio de Oliver), 32 (Cu├®llar-Delicias), 33 (Portillo-Pinares de Venecia) y 34 (Plaza de Espa├▒a-Cementerio). Las tres ├║ltimas l├¡neas eran un calco del servicio que proporcionaron las l├¡neas del tranv├¡a 5 y 8, pero en autob├║s era considerado menos provinciano. Al fondo, un troleb├║s de dos pisos de la l├¡nea Ciudad Jard├¡n se dirige a la terminal de la plaza de Santa Engracia. Esta l├¡nea ser├¡a clausurada al a├▒o siguiente. Tras ├®l emerge el bloque del n┬║ 7 de la plaza, el segundo en ser construido a finales de los a├▒os 60 sobre el antiguo "hotelito" del mismo n├║mero.', 1974, 1974, 1974, 'Anos 70', 'CENTRO', 41.64877700, -0.88509600, '0101000020E6100000D940BAD8B452ECBFD1B2EE1F0BD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51644006454.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51644006454.webp', 'https://www.flickr.com/photos/zaragozaantigua/51644006454/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24870, 'P┬║ de Pamplona 1915', 'Imagen capturada en el paseo de Pamplona durante el transcurso de la cabalgata organizada por el Centro Industrial durante las fiestas del Pilar del a├▒o 1915 que recorri├│ las principales calles del centro, integrada por una sucesi├│n de carrozas que representaban a algunos importantes comerciantes, fabricantes e industriales de la ciudad, adem├ís de a la propia comisi├│n de festejos y al Ayuntamiento. La de la imagen se corresponde con la carroza "estilo Luis XV" compuesta con el patrocinio del industrial chocolatero Joaqu├¡n Or├║s y que consigui├│ el tercer premio. Aparece estacionada ante la f├íbrica de conservas de Marraco.', 1915, 1915, 1915, 'Anos 10', 'CENTRO', 41.64820000, -0.88652300, '0101000020E61000009CDB847B655EECBF34A2B437F8D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/53458710901.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/53458710901.webp', 'https://www.flickr.com/photos/zaragozaantigua/53458710901/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25201, 'Monumento a Ram├│n de Pignatelli 1860', 'Glorieta de Pignatelli, con el monumento a Ram├│n de Pignatelli, obra de Antonio Jos├® Palao, inaugurado el 24 de junio de 1859, en conmemoraci├│n del aniversario del Canal Imperial de Arag├│n. Al fondo, la torre de la iglesia de Santa Engracia. Fuente visual: Mariano J├║dez y Ortiz. ├ülbum de Andr├®s Mart├¡n e Ip├ís. Colecci├│n Mariano Mart├¡n Casalderrey. Libro Primeros tiempos de la fotograf├¡a en Zaragoza', 1860, 1860, 1860, 'Siglo XIX', 'CENTRO', 41.64823300, -0.88485300, '0101000020E6100000438F183DB750ECBF0F98874CF9D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14710371517.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14710371517.webp', 'https://www.flickr.com/photos/zaragozaantigua/14710371517/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25202, 'Plaza de Arag├│n 1960', 'C├®sar Gracia Jarque. 1960. "Plaza de Arag├│n". Vista panor├ímica de buena parte de la Plaza de Arag├│n, muy arbolada, y chaleteada. Por detr├ís, despunta el Colegio de los PP. Jesuitas, y su contingente nueva Iglesia. A la derecha, la Plaza de Para├¡so, y la inmediata subida por el Paseo del General Mola.', 1960, 1960, 1960, 'Anos 60', 'CENTRO', 41.64867300, -0.88487600, '0101000020E61000004E7D2079E750ECBF2C6684B707D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14794033309.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14794033309.webp', 'https://www.flickr.com/photos/zaragozaantigua/14794033309/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25204, 'Plaza de Arag├│n 1946', 'AHPZ-Archivo Coyne, Manuel Coyne, 1940. Plaza de Arag├│n.', 1946, 1946, 1946, 'Anos 40', 'CENTRO', 41.64867300, -0.88487600, '0101000020E61000004E7D2079E750ECBF2C6684B707D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14863201816.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14863201816.webp', 'https://www.flickr.com/photos/zaragozaantigua/14863201816/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25206, 'Plaza de Arag├│n 1945', 'AHPZ. Archivo Estudio Coyne. Sobre el solar n┬║ 2 de la manzana "C" de la Expo de 1868 se levant├│ en 1888, proyectado por Antonio Miranda, un hotelito para Orencio Castellano. En 1916 y 1925 se reforma y ampl├¡a, entonces ya propiedad de Luis P├®rez Cistu├®. En 1944, para el mismo propietario, tiene lugar otra reforma y ampliaci├│n, tanto horizontal, como vertical, hasta dejarlo como ha llegado a nuestros d├¡as. De resultas de ello, el edificio es definido como ecl├®ctico, con elementos clasicistas, racionalistas, y regionalistas. En la imagen, el edificio tras su reforma de 1944, en una Plaza de Arag├│n a├║n territorio hotelito. En la actualidad es el ├║nico superviviente, como restaurante de luxe.', 1945, 1945, 1945, 'Anos 40', 'CENTRO', 41.64895300, -0.88504300, '0101000020E610000024B891B24552ECBF0FD253E410D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15318086359.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15318086359.webp', 'https://www.flickr.com/photos/zaragozaantigua/15318086359/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25626, 'Romareda 1970', 'Imagen del nuevo pol├¡gono Gran V├¡a, ya redenominado "Romareda", en plena ebullici├│n edilicia. La captura se ha realizado desde el ancho vial de nombre Eduardo Ibarra, con un vistazo hacia el suroeste. En primer plano, de izquierda a derecha, las torres de los n├║meros 6 y 4 de la que luego ser├¡a nueva calle Juan II de Arag├│n, y la torre n┬║ 15 de la prolongaci├│n de la calle de As├¡n y Palacios. Detr├ís de ellas, distintos momentos constructivos de otros edificios poligoneros. El panorama est├í a├║n tan despejado que es posible, incluso, ver todav├¡a los m├ís veteranos bloques del arranque de la V├¡a de la Hispanidad, al fondo, a la izquierda. Fuente visual: foto Gerardo Sancho Ramo, AMZ.', 1970, 1970, 1970, 'Anos 70', 'UNIVERSIDAD', 41.63650200, -0.90367900, '0101000020E61000009D9FE238F0EAECBF57EBC4E578D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32841092572.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32841092572.webp', 'https://www.flickr.com/photos/zaragozaantigua/32841092572/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25208, 'Sal├│n de Pignatelli c.1877', 'Inaugurado en 1859, este gran bulto redondo del orondo Pignatelli fue elemento central en la Primera Exposici├│n Aragonesa (setiembre-noviembre 1868), ubicada en el nov├¡simo recinto del Sal├│n de Pignatelli (antes, Prado de San Jer├│nimo). A pesar de que el Palacio de la Exposici├│n (edificio principal de la misma), hab├¡a sido erigido con la intenci├│n de que permaneciera, y fuera el pionero de una pronta urbanizaci├│n de la virgen zona, la penuria econ├│mica municipal hizo que fuera piqueteado para vender el suelo que ocupaba, aunque el proceloso proceso de urbanizaci├│n se extender├¡a hasta entrado el siglo XX, marcado siempre por los intereses particulares de los propietarios del suelo. Cosas de emprendedores, que funcionaban as├¡. Tal que ahora. De haberse mantenido, ese Palacio hubiera definido una nueva traza de la plaza, pues estaba justo en medio de la actual calle Canfranc, y hubiera lucido justo a la derecha del antiguo edificio de Capitan├¡a. En la imagen, la estatua de Pignatelli en el despejado entorno de la glorieta a la que daba nombre. A su izquierda, los edificios del "Parque de Ingenieros", que desde 1861 estaba ubicado en el antiguo convento de las Carmelitas Descalzas de San Jos├®, del que se conservaba la iglesia, el claustro, bodegas... Luego ser├í sede del Gobierno Militar de Zaragoza. La "Operaci├│n Cuarteles" de los a├▒os 70 del pasado siglo lo convertir├í en propiedad municipal. Tras la estatua, en el centro, los edificios de la calle de la Independencia se proyectan hacia la plaza de la Constituci├│n, comenzando con el reciente "Teatro de Novedades" (1864). Qu├® lejos quedaba Zaragoza, all├í al fondo...', 1877, 1877, 1877, 'Siglo XIX', 'CENTRO', 41.64827100, -0.88482300, '0101000020E610000099F4F7527850ECBFFDF84B8BFAD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/16296666795.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/16296666795.webp', 'https://www.flickr.com/photos/zaragozaantigua/16296666795/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25209, 'Calle Ponzano 8, 1897', 'Edificio de la f├íbrica de espejos "La Veneciana", de Basilio Para├¡so, en la calle Ponciano Ponzano 8. La tienda se encontraba en la calle del Coso 6. Se anunciaba ofreciendo "Decorado de iglesias, salones y fachadas. Talla y marqueter├¡a en toda clase de maderas, cart├│n, pasta y piedra. Persianas. Cromos, oleograf├¡a y estampas en litograf├¡a, lunas y cristales. Vidrios planos de muselinas y colores. Diamantes para cortarlos". La f├íbrica hab├¡a estado en la plaza de Santa Engracia (1876-1880), y a partir de 1897 en el Camino de los Cubos. Fuente: M┬¬ Pilar Biel Ib├í├▒ez, Zaragoza y la industrializaci├│n: la arquitectura industrial 1875-1936, IFC, 2004.', 1897, 1897, 1897, 'Siglo XIX', 'CENTRO', 41.64924900, -0.88521500, '0101000020E61000006BB75D68AE53ECBFF8FA5A971AD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19804027945.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19804027945.webp', 'https://www.flickr.com/photos/zaragozaantigua/19804027945/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25210, 'Plaza de Arag├│n c.1955', 'Foto: Jos├® Antonio Duce. Imagen nocturna de la plaza de Arag├│n de Zaragoza. Fuente: rafaelcastillejo.com', 1955, 1955, 1955, 'Anos 50', 'CENTRO', 41.64855100, -0.88471200, '0101000020E6100000BD1E4C8A8F4FECBFE0641BB803D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20719568641.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20719568641.webp', 'https://www.flickr.com/photos/zaragozaantigua/20719568641/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25211, 'Torre del Pino 1865', 'Plano de la Torre del Pino, Antonio Berbegal, Zaragoza, 1865. Detalle de las plantaciones del vivero municipal de la Torre del Pino. Estos terrenos estaban situados entre las actuales calles de Bilbao y Ponciano Ponzano. A la izquierda, el ramal de la acequia de la Romareda que llegaba hasta all├¡; abajo, un peque├▒o tramo del actual paseo de Pamplona. En poco tiempo, las plantaciones ser├ín sustituidas por el edificio principal de la Exposici├│n Aragonesa de 1868. Fuente: AMZ', 1865, 1865, 1865, 'Siglo XIX', 'CENTRO', 41.64827900, -0.88635300, '0101000020E610000082C476F7005DECBF80D767CEFAD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21055742855.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21055742855.webp', 'https://www.flickr.com/photos/zaragozaantigua/21055742855/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25212, 'Pl. de Arag├│n 1957', 'Imagen en altura del soto de la plaza de Arag├│n, cuando a├║n era un espacio provinciano carente de los atractivos que una ciudad moderna debe ofrecer. Unos pocos a├▒os despu├®s, se pusieron las cosas en su sitio. Fuente visual: www.delcampe.net', 1957, 1957, 1957, 'Anos 50', 'CENTRO', 41.64836500, -0.88495900, '0101000020E6100000AEA069899551ECBF7E6FD39FFDD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21526330441.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21526330441.webp', 'https://www.flickr.com/photos/zaragozaantigua/21526330441/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25213, 'Pl. de Arag├│n 1954', 'Imagen convertida en postal por Ediciones Sicilia, y titulada "Plaza de Arag├│n y paseo de Independencia". Visual en altura, posiblemente desde el edicicio "El├¡seos", donde ya se evidencia un colapso circulatorio que s├│lo podr├í ser solucionado mediante la necesaria conversi├│n del paseo en una multiautopista, unos a├▒os despu├®s. Y de paso, ser├í posible sustituir la provinciana estampa de hotelitos de la plaza de Arag├│n, por modernos edificios a la altura de los tiempos, en una ciudad con un glorioso pasado, y un deslumbrante futuro. El troleb├║s y el tranv├¡a, que parecen como esconderse, no se librar├ín de esta pactada transici├│n. Fuente visual: www.delcampe.net/', 1954, 1954, 1954, 'Anos 50', 'CENTRO', 41.64836500, -0.88489400, '0101000020E6100000E7A6CD380D51ECBF7E6FD39FFDD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/26557498400.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/26557498400.webp', 'https://www.flickr.com/photos/zaragozaantigua/26557498400/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25214, 'Plaza de Arag├│n c.1962', 'Vista de la plaza de Arag├│n. Al fondo, edificio El├¡seos con su peineta, en el chafl├ín entre el paseo del General Mola y el de Calvo Sotelo. Fuente: Foto para postal de Comercial Josan. Cesi├│n de la familia de Jos├® Mar├¡a Sanz Gonz├ílez a Rafael Castillejo. Dataci├│n y procesado:', 1962, 1962, 1962, 'Anos 60', 'CENTRO', 41.64836500, -0.88489400, '0101000020E6100000E7A6CD380D51ECBF7E6FD39FFDD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/26813015893.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/26813015893.webp', 'https://www.flickr.com/photos/zaragozaantigua/26813015893/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25215, 'Monumento a Ram├│n de Pignatelli 1861', 'Glorieta de Pignatelli, con el monumento a Ram├│n de Pignatelli, obra de Antonio Jos├® Palao, inaugurado el 24 de junio de 1859, en conmemoraci├│n del aniversario del Canal Imperial de Arag├│n. Al fondo, la Segunda Puerta de Santa Engracia. Fuente: Mariano J├║dez y Ortiz. ├ülbum de Andr├®s Mart├¡n e Ip├ís. Colecci├│n Mariano Mart├¡n Casalderrey. Libro Primeros tiempos de la fotograf├¡a en Zaragoza', 1861, 1861, 1861, 'Siglo XIX', 'CENTRO', 41.64836500, -0.88489400, '0101000020E6100000E7A6CD380D51ECBF7E6FD39FFDD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/28299361240.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/28299361240.webp', 'https://www.flickr.com/photos/zaragozaantigua/28299361240/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25216, 'Vista a├®rea plaza Arag├│n 1957', 'Vista a├®rea de la plaza de Arag├│n y su entorno. Al fondo, el Pilar. Abajo, la Facultad de Medicina y Ciencias. Fuente: TAF Helic├▓pters. Arxiu Nacional de Catalunya.', 1957, 1957, 1957, 'Anos 50', 'CENTRO', 41.64839400, -0.88487500, '0101000020E610000037894160E550ECBF19761893FED24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30988351620.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30988351620.webp', 'https://www.flickr.com/photos/zaragozaantigua/30988351620/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25217, 'Pl. de Arag├│n 1955', 'Imagen, capturada desde cierta altura, centrada en la antigua plaza de Arag├│n. Al fondo, el antiguo paseo de la Independencia. Fuente visual: www.delcampe.es', 1955, 1955, 1955, 'Anos 50', 'CENTRO', 41.64834900, -0.88470100, '0101000020E6100000C2A1B778784FECBF79B29B19FDD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31063043780.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31063043780.webp', 'https://www.flickr.com/photos/zaragozaantigua/31063043780/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25220, 'Pl. de Arag├│n 1957', 'Imagen capturada desde la notable altura del Banco de Cr├®dito de Zaragoza, sito al final del paseo de la Independencia, con una interesante panor├ímica centrada en el inmediato entorno de la vecina plaza de Arag├│n. El Monumento al Justiciazgo hace de eje de esta verde y recoleta glorieta cuya traza todav├¡a recuerda los tiempos en que la figura de Ram├│n Pignatelli presid├¡a este espacio. Alrededor, los hotelitos de los n├║meros 6, 7 y 8, a la izquierda; la Capitan├¡a General y el n┬║ 10, a la derecha, donde circula una composici├│n de la tranviaria l├¡nea 5. Torrero-Delicias. M├ís all├í, la plaza de Basilio Para├¡so, donde transita un troleb├║s de regreso de la l├¡nea Terminillo, y un coche posiblemente de la l├¡nea del tranv├¡a 15. Casablanca. El Edificio El├¡seos y la antigua Facultad de Medicina y Ciencias jalonan el arranque de los paseos del General Mola, de Calvo Sotelo, y de Pamplona. A la izquierda y escalonados, los grandes colegios del Salvador, y del Sagrado Coraz├│n de Jes├║s. Por encima y al fondo, tras el ascenso por las terrazas de Cu├®llar, se destaca la torre del Sacrario Militare Italiano. Fuente visual: AMZ', 1957, 1957, 1957, 'Anos 50', 'CENTRO', 41.64836500, -0.88488200, '0101000020E6100000D6355A0EF450ECBF7E6FD39FFDD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/47017652142.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/47017652142.webp', 'https://www.flickr.com/photos/zaragozaantigua/47017652142/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25221, 'Pl. de Arag├│n 1955', 'Al nivel de los peatones, imagen de una luminosa tarde de paseo por la antigua plaza de Arag├│n, que fuera Glorieta de Pignatelli hasta que a principios del siglo XX las elites locales erigieran el Monumento al Justiciazgo desplazando al ilustrado Pignatelli de esta ubicaci├│n al ostracismo de la sure├▒a periferia, junto a los Dep├│sitos de Agua de la ciudad. Al fondo y a la izquierda, el hotelito del n┬║ 13 de la plaza, recayente a la calle de Jos├® Luis Albareda. Tras ├®l, la monumental manzana del Banco de Cr├®dito de Zaragoza, en cuya planta calle el Caf├® Ambos Mundos estaba por cerrarse, tras 74 a├▒os desde su inauguraci├│n. Tras el Justiciazgo, el cenotafio "A los funcionarios muertos en agosto de 1920", y el bulevar del paseo de la Independencia. Fuente visual: AMZ', 1955, 1955, 1955, 'Anos 50', 'CENTRO', 41.64836500, -0.88488200, '0101000020E6100000D6355A0EF450ECBF7E6FD39FFDD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/47096051531.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/47096051531.webp', 'https://www.flickr.com/photos/zaragozaantigua/47096051531/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25222, 'Pl. de Arag├│n c.1895', 'In├®dita imagen parcial de la plaza de Arag├│n capturada desde la altura del inmueble del n┬║ 3, con el fondo edilicio de la Capitan├¡a General, a la izquierda, y el inmueble del n┬║ 10 a la derecha, que destaca por el caracter├¡stico aspecto coronado con cupulines laterales tras la reforma proyectada por Fernando de Yarza. La glorieta sigue presidida por el orondo bulto redondo del pr├│cer Pignatelli rodeado de verjas y exuberante vegetaci├│n, mirando hacia el sur, hacia el Canal Imperial.', 1895, 1895, 1895, 'Siglo XIX', 'CENTRO', 41.64832800, -0.88477400, '0101000020E61000003E3C4B901150ECBF618A7269FCD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/48039751732.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/48039751732.webp', 'https://www.flickr.com/photos/zaragozaantigua/48039751732/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24898, 'Universidad Laboral 1975', 'Archivo Municipal Zaragoza. Gerardo Sancho Ramo. 15/07/1975. En 1967, el Ayuntamiento cedi├│ 200.000 m2 de terreno al Ministerio de Trabajo para la construcci├│n de una Universidad Laboral Femenina en el barrio de Santa Isabel, a 11 km del centro urbano. En octubre de ese a├▒o fue inaugurada, y permaneci├│ activa hasta 1978, en que desaparecen las Universidades Laborales. En la imagen, actividades deportivas en las instalaciones para la pr├íctica de atletismo.', 1975, 1975, 1975, 'Anos 70', NULL, 41.65257700, -0.79263500, '0101000020E61000005A475513445DE9BF978FA4A487D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15268306596.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15268306596.webp', 'https://www.flickr.com/photos/zaragozaantigua/15268306596/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25225, 'Plaza de Arag├│n 1954', 'Imagen capturada en altura desde el Edificio El├¡seos y centrada en la plaza de Arag├│n precedida por el antiguo paseo de la Independencia. La arbolada plaza presenta su tradicional estampa de hotelitos, a la izquierda los de los n├║meros 12 y 13, a la derecha los de los n├║meros 1, 2 y 8. El bulevar de Independencia arranca de la plaza de Espa├▒a donde luce la fachada del Coso recayente a ella. Como tel├│n de fondo emergen, de izquierda a derecha, la torre del reloj del Banco de Arag├│n, las dos torres sure├▒as del Pilar, la c├║pula sobre el torre├│n del Banco Zaragozano, y la torre y cimborrio de la Seo Esta imagen fue tambi├®n comercializada como postal y por la misma empresa, en una versi├│n m├ís luminosa y sin recortar por la parte de la derecha y la inferior, donde aparec├¡an un troleb├║s y un tranv├¡a maniobrando en la linde con la plaza de Basilio Para├¡so. Esta otra imagen ya la tenemos incorporada en el', 1954, 1954, 1954, 'Anos 50', 'CENTRO', 41.64830400, -0.88489200, '0101000020E6100000BABE0F070951ECBFD9EE1EA0FBD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/48948253206.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/48948253206.webp', 'https://www.flickr.com/photos/zaragozaantigua/48948253206/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25226, 'Plaza de Arag├│n 1950', 'Estupenda imagen capturada en la antigua plaza de Arag├│n, cuando a├║n manten├¡a el esp├¡ritu de la original glorieta de Pignatelli, con el valor a├▒adido de la frondosa vegetaci├│n que la caracterizaba, antes de la radical reforma de principios de la siguiente d├®cada. Centra la imagen el Monumento al medieval Justiciazgo que la elite local impuso a la original del pr├│cer ilustrado, desplazado como sus ideas a la lejana periferia sure├▒a. Detr├ís y a la izquierda, el rotundo edificio del Banco de Cr├®dito de Zaragoza emerge sobre el hotelito del n┬║ 13 de la plaza.', 1950, 1950, 1950, 'Anos 50', 'CENTRO', 41.64814400, -0.88486000, '0101000020E6100000E23B31EBC550ECBFA08CF161F6D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/48959425861.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/48959425861.webp', 'https://www.flickr.com/photos/zaragozaantigua/48959425861/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25227, 'Plaza de Arag├│n c.1958', 'Imagen capturada en original blanco y negro junto al Monumento al Justiciazgo sito en la plaza de Arag├│n, y coloreada posteriormente a mano para ser editada como postal. Hacia el fondo, vista del frondoso bulevar del paseo de la Independencia centrada por el cenotafio "A los funcionarios muertos en agosto de 1920". Esta tradicional zona de paseo y esparcimiento social desaparecer├¡a poco despu├®s en beneficio de la hegem├│nica circulaci├│n rodada.', 1958, 1958, 1958, 'Anos 50', 'CENTRO', 41.64854400, -0.88482800, '0101000020E61000000AB952CF8250ECBF2E02637D03D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/49137699773.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/49137699773.webp', 'https://www.flickr.com/photos/zaragozaantigua/49137699773/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25228, 'Plaza de Arag├│n c.1954', 'Imagen capturada desde la altura del antiguo inmueble del n┬║ 8 de la plaza de Arag├│n, con una vista del inmediato espacio arbolado de la plaza centrado desde 1904 por el Monumento al Justiciazgo. El entorno edilicio segu├¡a definido por la planta de los decimon├│nicos hotelitos, alguno recrecido recientemente, como el del n┬║ 12, a la izquierda de la escena. Hacia el fondo, el bulevar que conformaba el antiguo paseo de la Independencia. En primer t├®rmino y a la derecha, circula una unidad de la serie 200 en servicio en la l├¡nea 11. Parque, que sigue a una composici├│n de la l├¡nea 5. Venecia-Delicias, ambas encaminadas hacia la plaza de Espa├▒a.', 1954, 1954, 1954, 'Anos 50', 'CENTRO', 41.64836800, -0.88476400, '0101000020E61000005BB39597FC4FECBFEFE2FDB8FDD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/49273387833.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/49273387833.webp', 'https://www.flickr.com/photos/zaragozaantigua/49273387833/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25232, 'Glorieta de Pignatelli 1878', 'Imagen capturada por el fot├│grafo villanovense Gregorio Sabat├® F├®rriz e integrada en el ├ílbum "Vistas de Zaragoza", que se centra en este gran bulto redondo del orondo Ram├│n Pignatelli Moncayo Inaugurado en 1859 como elemento central del escenario donde tuvo lugar la Primera Exposici├│n Aragonesa entre setiembre y noviembre de 1868, ubicada en el nov├¡simo recinto del Sal├│n de Pignatelli que antes fuera denominado Prado de San Jer├│nimo. A pesar de que el Palacio de la Exposici├│n, el edificio principal de la misma, hab├¡a sido erigido con la intenci├│n de que permaneciera y fuera el pionero de una pronta urbanizaci├│n de esta zona, pero la penuria econ├│mica municipal hizo que fuera derribado para vender el suelo que ocupaba, aunque el proceloso proceso de urbanizaci├│n se extender├¡a hasta entrado el siglo XX, marcado siempre por los intereses particulares de los propietarios del suelo que fueron construyendo sus respectivos "hotelitos" al ritmo que mejor les pareci├│. En la imagen, la estatua dedicada a Pignatelli en el despejado entorno de la arbolada glorieta a la que daba nombre. Tras la estatua rodeada de verja y a la izquierda, espacio donde pronto ser├¡a construido el primero de los "hotelitos" de la glorieta. A la derecha, edificios del lado de los pares de la calle de la Independencia que se proyectan hacia la plaza de la Constituci├│n, comenzando con el reciente Teatro de Novedades.', 1878, 1878, 1878, 'Siglo XIX', 'CENTRO', 41.64814400, -0.88510700, '0101000020E6100000D3BD4EEACB52ECBFA08CF161F6D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/54751914094.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/54751914094.webp', 'https://www.flickr.com/photos/zaragozaantigua/54751914094/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25257, 'Vista paseo Pamplona c.1900', 'Vista de Zaragoza y sus torres desde la Facultad de Medicina y Ciencias. En primer plano, paseo de la Lealtad, luego de Pamplona. En el centro, ante el cuartel de Artiller├¡a del Carmen, la iglesia de las Esclavas del Sagrado Coraz├│n, en la esquina de la calle de Teruel (luego de Bilbao) con la de Canfranc. Fuente: Foto Alday, en www.kutxateka.eus/', 1900, 1900, 1900, 'Anos 1900', 'CENTRO', 41.64893400, -0.88630900, '0101000020E61000009AD024B1A45CECBF98A1F14410D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/37971354276.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/37971354276.webp', 'https://www.flickr.com/photos/zaragozaantigua/37971354276/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25310, 'Pl. de Arag├│n c.1985', 'Vista de la plaza de Arag├│n y el paseo de la Independencia a principios de los a├▒os 80. Al fondo despunta el Pilar. Fuente: www.facebook.com/photo.php?fbid=1581258498769047&set=...', 1985, 1985, 1985, 'Anos 80', 'CENTRO', 41.64859900, -0.88466800, '0101000020E6100000D42AFA43334FECBFF19BC24A05D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21699721105.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21699721105.webp', 'https://www.flickr.com/photos/zaragozaantigua/21699721105/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25467, 'Esclavas del Sagrado Coraz├│n de Jes├║s 1895', 'Archivo y Hemeroteca Municipales de Zaragoza, 1895. Interior del templo de las Esclavas del Sagrado Coraz├│n de Jes├║s, en la confluencia de las calles Canfranc y Bilbao de Zaragoza. Proyecto ecl├®ctico de Ricardo Magdalena de 1890, inaugurado en 1895 y derribado en 1968 (ver imagen del derribo aqu├¡: www.flickr.com/photos/126653716@N03/14918421485/in/photol...). Fuente: "Ricardo Magdalena. Arquitecto municipal de Zaragoza". IFC, 2012.', 1895, 1895, 1895, 'Siglo XIX', 'CENTRO', 41.64895600, -0.88612400, '0101000020E61000002B6C06B8205BECBF80457EFD10D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15541400535.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15541400535.webp', 'https://www.flickr.com/photos/zaragozaantigua/15541400535/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25492, 'Plaza del Carmen 1963', 'Vista a├®rea capturada sobrevolando la plaza del Carmen y centrando el objetivo donde estuviera el antiguo y hom├│nimo cuartel del ej├®rcito, que ya derribado, su solar era utilizado provisionalmente para acoger espect├ículos circenses por ejemplo durante las Fiestas del Pilar, como es el caso. El festivo per├¡metro ocupado por el Circo Monumental, est├í delimitado entre las calles de la Vieja Guardia (actual de Marcelino de Is├íbal), Capit├ín Portol├®s (actual del Doctor Val-Carreres), y General Sanjurjo (actual tramo de la avenida de C├®sar Augusto). Hacia la izquierda, la imponente presencia del Front├│n Aragon├®s, recayente a la calle de Jos├® Luis Albareda. Al fondo, el punto de confluencia entre el paseo de Pamplona, la calle de Hern├ín Cort├®s y el arranque del paseo de Mar├¡a Agust├¡n.', 1963, 1963, 1963, 'Anos 60', 'CENTRO', 41.65076500, -0.88521400, '0101000020E610000054C37E4FAC53ECBFD3307C444CD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50833723873.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50833723873.webp', 'https://www.flickr.com/photos/zaragozaantigua/50833723873/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (26016, 'Vista c.1944', 'Desde la altura del Edificio El├¡seos, vista orientada hacia la plaza de Arag├│n y el paseo de la Independencia. La plaza sigue siendo un espacio definido por la continuidad del bulevar y la escala urban├¡stica de los hotelitos que la rodean, si bien en la imagen destacan las obras de remodelaci├│n de dos de sus inmuebles. A la derecha y con andamios de obra, la ampliaci├│n en altura y volumen hasta el paseo de Marina Moreno del n┬║ 4, con proyecto del arquitecto Fausto Garc├¡a Marco. Confrontando y al otro lado de la plaza, el antiguo n┬║ 12 proyectado por Antonio Miranda en 1888, para el que Miguel ├üngel Navarro P├®rez y Jos├® Luis Navarro Anguela hab├¡an ideado una radical ampliaci├│n y reforma que comenzar├¡a poco despu├®s. Adem├ís, destaca la cobertura en ca├▒izo que se├▒ala la reforma del veterano inmueble del n┬║ 37 del paseo de la Independencia, esquinero con la calle de Juan Bruil.', 1944, 1944, 1944, 'Anos 40', 'CENTRO', 41.64841500, -0.88489300, '0101000020E6100000D1B2EE1F0B51ECBF309E4143FFD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22556709864.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22556709864.webp', 'https://www.flickr.com/photos/zaragozaantigua/22556709864/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (26043, 'Plaza de Arag├│n 1963', 'Imagen capturada desde cierta altura, lo que permite una buena visual de las plazas de Para├¡so, Arag├│n, y el paseo de la Independencia, tras su conversi├│n en v├¡as de alta capacidad para tr├ífico rodado por el interior de la ciudad. Al fondo, ins├│lita visi├│n de las chimeneas de la antigua azucarera del Arrabal, sobresaliendo por encima de la antigua fachada de edificios del Coso. Una unidad 200, hacia el paseo de Calvo Sotelo, y otra de la l├¡nea "Torrero-Delicias", hacia el paseo del General Mola. Fuente visual: www.delcampe.es', 1963, 1963, 1963, 'Anos 60', 'CENTRO', 41.64834900, -0.88470100, '0101000020E6100000C2A1B778784FECBF79B29B19FDD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31417914755.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31417914755.webp', 'https://www.flickr.com/photos/zaragozaantigua/31417914755/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (26071, 'Plaza de Arag├│n, 1963', 'Vista a├®rea capturada sobrevolando el entorno de la plaza de Arag├│n, definida por el contraste entre la nueva autopista que conectaba la plaza de Espa├▒a y la de Basilio Para├¡so, y la presencia de los venerables hotelitos que, aun bastante modificados, perduraban en ambos lados de la plaza desde su establecimiento a finales del siglo XIX. Este contraste empez├│ a desaparecer cuando los hotelitos fueron sustituidos por los actuales edificios comerciales y residenciales que los sustituyeron en los a├▒os y d├®cadas siguientes. Hacia el fondo destaca la gran estructura del Front├│n Aragon├®s, y la c├║pula de la iglesia de Santiago el Mayor y la torre de San Pablo hacia la derecha. El desarrollismo estaba a punto de modificar radicalmente lo que aparece en esta vista, con el surgimiento de algunos de los locales rascacielos de la ciudad.', 1963, 1963, 1963, 'Anos 60', 'CENTRO', 41.64844800, -0.88493500, '0101000020E61000008CBE82346351ECBF0C94145800D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50836749018.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50836749018.webp', 'https://www.flickr.com/photos/zaragozaantigua/50836749018/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (26073, 'Plaza de Arag├│n, 1925', 'Bien interesante vista a├®rea centrada en la plaza de Arag├│n y el paseo de la Independencia, que arranca en la parte superior de la plaza de la Constituci├│n. A la derecha, el entorno de la antigua Huerta de Santa Engracia, todav├¡a ocupado en parte por el Saturno Park.', 1925, 1925, 1925, 'Anos 20', 'CENTRO', 41.64854400, -0.88480700, '0101000020E61000002DB308C55650ECBF2E02637D03D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51099057799.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51099057799.webp', 'https://www.flickr.com/photos/zaragozaantigua/51099057799/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (20946, 'Puerta del Carmen 1808', 'Juramento de los defensores de Zaragoza en la plazuela del Carmen, Nicol├ís Ruiz de Valdivia, ├│leo sobre lienzo, 1866. Depositado en las Cortes de Arag├│n. "La Junta de Salvaci├│n nombrada el 24 de junio de 1808 en Zaragoza, arengando a los defensores del reducto de la Puerta del Carmen. El Marqu├®s de Laz├ín, hermano de Palafox, toma juramento a los defensores de Zaragoza ante una bandera blanca con una ense├▒a central representando la Virgen del Pilar. La representaci├│n es interesante por reflejar monumentos desaparecidos en los Sitios: la torre del Pino, la antigua c├║pula de la iglesia de san Ildefonso, y el remate (el le├│n rampante del escudo de Zaragoza) de la puerta del Carmen (en la actualidad, desaparecido). A la derecha se reconoce a Mariano Cerezo, con sable y chistera, inspirado en el grabado de G├ílvez y Brambila." Fuente: agustinazaragoza.wordpress.com/2014/06/24/24-de-junio-de-...', 1808, 1808, 1808, 'Siglo XIX', 'CENTRO', 41.64961200, -0.88779200, '0101000020E610000057D0B4C4CA68ECBF698B6B7C26D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15012554499.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15012554499.webp', 'https://www.flickr.com/photos/zaragozaantigua/15012554499/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (20966, 'Puerta del Carmen 1815', 'Pintura de ├üngel D├¡az Dom├¡nguez, realizada en 1927, con una recreaci├│n ecl├®ctica, castiza y regionalista, de una procesionaria de majos y majas que, desde el Paseo de las Tapias, entran a Zaragoza por una puerta del Carmen ya da├▒ada por los sucesos b├®licos de 1808-1809. Al fondo, los otros edificios representativos de la zona (Convento de la Encarnaci├│n, iglesia de San Ildefonso) aparecen dispuestos muy libremente. Si las figuras pretenden ser muy goyescas, pero del Goya de antes de 1808, la pincelada y los colores son m├ís de Zuloaga. Fuente visual: "Artistas aragoneses desde Goya a nuestros d├¡as", Ayto. Zaragoza, 1991.', 1815, 1815, 1815, 'Siglo XIX', 'CENTRO', 41.64982500, -0.88759100, '0101000020E61000007C2AA73D2567ECBFC58F31772DD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/18901770383.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/18901770383.webp', 'https://www.flickr.com/photos/zaragozaantigua/18901770383/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21006, 'Puerta del Carmen c.1860', '"Puerta del Carmen en Zaragoza". La Puerta parece una puerta, e indica el ancho de la calle a la que da acceso. Al fondo, a la izquierda, la c├║pula de la Iglesia del antiguo convento dominico de San Ildefonso (antes de ser destruida por un rayo) y, m├ís cercana, la c├║pula de media naranja del convento de la Encarnaci├│n. Por el vano central de la puerta, entre ├írboles, surge la Torre Nueva, y su triple chapela barroca. Fuente visual: Autor an├│nimo, Colecci├│n Madrazo, proveniente de la familia Daza Campos (Adquirida por el Museo del Prado)', 1860, 1860, 1860, 'Siglo XIX', 'CENTRO', 41.64982700, -0.88754200, '0101000020E61000002272FA7ABE66ECBF6687F8872DD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14911532362.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14911532362.webp', 'https://www.flickr.com/photos/zaragozaantigua/14911532362/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21016, 'Puerta del Carmen 1867', '"Puerta de Nuestra Se├▒ora del C├írmen, en Zaragoza", xilograf├¡a de Tom├ís Carlos Capuz incluida en la Cr├│nica general de Espa├▒a, Madrid, 1867.', 1867, 1867, 1867, 'Siglo XIX', 'CENTRO', 41.64982500, -0.88759100, '0101000020E61000007C2AA73D2567ECBFC58F31772DD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19346051710.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19346051710.webp', 'https://www.flickr.com/photos/zaragozaantigua/19346051710/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21187, 'Puerta del Carmen c.1898', 'Puerta del Carmen, vista desde el paseo de la Lealtad. El almac├®n de sal de la derecha dar├í paso a├▒os despu├®s al Caf├® Levante (fundado en 1895 y situado all├¡ en 1903, aproximadamente). Fuente visual: Foto Alday, en www.kutxateka.eus/', 1898, 1898, 1898, 'Siglo XIX', 'CENTRO', 41.64983200, -0.88772500, '0101000020E610000063EE5A423E68ECBF78F2E9B12DD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/37931235106.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/37931235106.webp', 'https://www.flickr.com/photos/zaragozaantigua/37931235106/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21217, 'Convento de la Encarnaci├│n 1907', 'Postal. "Colecci├│n Patria y Fe n├║m. 32, Zaragoza 1908 - Centenario de los Sitios", 1907. "De edificaci├│n reciente; construido en el solar del antiguo convento de la Encarnaci├│n que destruyeron los franceses. Su proximidad a la puerta del Carmen, le hizo punto muy estrat├®gico para la defensa, como tambi├®n lo fueron el convento y el colegio del Carmen inmediatos, donde hoy se encuentran la Escuela de Veterinaria y el Cuartel de Artiller├¡a." Convento de la Encarnaci├│n de las Madres Carmelitas, en el actual chafl├ín de C├®sar Augusto con el paseo Mar├¡a Agust├¡n. Sustituido por otro en la misma ubicaci├│n. Vista trasera. Fuente: www.pasapues.es/', 1907, 1907, 1907, 'Anos 1900', 'CENTRO', 41.65019300, -0.88779100, '0101000020E610000040DCD5ABC868ECBF488B338639D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15572137949.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15572137949.webp', 'https://www.flickr.com/photos/zaragozaantigua/15572137949/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21255, 'Puerta del Carmen 1907', 'Postal. "Colecci├│n Patria y Fe n├║m. 21, Zaragoza 1908 - Centenario de los Sitios", 1907. "De donde fueron siempre rechazados los franceses en sus porfiados ataques. En uno de ellos fue muerto el valiente patriota Romeo, capit├ín retirado y natural de Tudela. En torno a esta puerta, verdadero monumento nacional, se proyecta hoy la formaci├│n de una gran plaza." Fuente: www.pasapues.es/', 1907, 1907, 1907, 'Anos 1900', 'CENTRO', 41.64982500, -0.88759100, '0101000020E61000007C2AA73D2567ECBFC58F31772DD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20582349650.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20582349650.webp', 'https://www.flickr.com/photos/zaragozaantigua/20582349650/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21257, 'Cuartel de Hern├ín Cort├®s 1907', 'Postal. "Colecci├│n Patria y Fe n├║m. 23, Zaragoza 1908 - Centenario de los Sitios", 1907. "Situado en el camino viejo de Casa-Blanca, por donde los franceses hab├¡an de acercarse a Zaragoza, el pueblo llev├│ all├¡ sus avanzadas para libra a la ciudad de la aproximaci├│n de los invasores. Era entonces un convento de frailes capuchinos. Cuando los franceses se posesionaron de ├®l, repleg├íronse nuestras tropas hacia la puerta del Carmen." Fuente: www.pasapues.es/', 1907, 1907, 1907, 'Anos 1900', 'CENTRO', 41.64878500, -0.88904500, '0101000020E6100000A583F57F0E73ECBF53910A630BD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20582662528.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20582662528.webp', 'https://www.flickr.com/photos/zaragozaantigua/20582662528/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21292, 'Puerta del Carmen c.1908', 'Vista de la Puerta del Carmen y su paisanaje, desde su antiguo lado exterior o extramuros. Fuente visual: Foto para postal de Comercial Josan. Cesi├│n de la familia de Jos├® Mar├¡a Sanz Gonz├ílez a Rafael Castillejo. Dataci├│n y procesado:', 1908, 1908, 1908, 'Anos 1900', 'CENTRO', 41.64985800, -0.88766100, '0101000020E6100000B4E89D0AB867ECBFA185048C2ED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/27369997886.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/27369997886.webp', 'https://www.flickr.com/photos/zaragozaantigua/27369997886/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21328, 'Puerta del Carmen c.1908', 'Imagen de la Puerta del Carmen en su tradicional entorno de la encrucijada entre el paseo de Mar├¡a Agust├¡n (izquierda), el paseo de Pamplona (derecha), la calle de Hern├ín Cort├®s (hacia la izquierda) y la arbolada calle de la Soberan├¡a Nacional (hacia el fondo). La puerta conserva todav├¡a los ├║ltimos postigos de madera de su paso central, as├¡ como los cilindros de piedra que lo proteg├¡an del tr├ínsito de veh├¡culos rodados. Flanquean la puerta tenderetes festivos. Hemos volteado horizontalmente la imagen original para que el convento de la Encarnaci├│n del fondo no pierda el norte.', 1908, 1908, 1908, 'Anos 1900', 'CENTRO', 41.64985900, -0.88765000, '0101000020E6100000BA6B09F9A067ECBF710168942ED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50165660223.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50165660223.webp', 'https://www.flickr.com/photos/zaragozaantigua/50165660223/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21359, 'Puerta del Carmen 1900', 'Imagen capturada en el arranque del paseo de Mar├¡a Agust├¡n y centrada en la Puerta del Carmen tras que que daba comienzo la arbolada calle de la Soberan├¡a Nacional donde a la derecha, a continuaci├│n de los edificios de la fotograf├¡a, quedaba el Dep├│sito de Cad├íveres de la ciudad.', 1900, 1900, 1900, 'Anos 1900', 'CENTRO', 41.64986700, -0.88766000, '0101000020E61000009DF4BEF1B567ECBFF4DF83D72ED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/54785920358.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/54785920358.webp', 'https://www.flickr.com/photos/zaragozaantigua/54785920358/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21510, 'Sommiers Andr├®s Luc├¡a 1926', 'Antonio Beter├® Salvador naci├│ en la ciudad en 1899, en familia pobre. Consigui├│ estudiar, y entr├│ a trabajar con su t├¡o Andr├®s Luc├¡a Borge, propietario de un peque├▒o taller de reparaci├│n de jergones, para llevar la contabilidad. Las cosas iban bien, a su t├¡o le toc├│ la loter├¡a, y con el capital obtenido ampliaron las instalaciones fabriles de la calle Las Mercedes n┬║ 14. Ya en los a├▒os 20, pasaron de la mera reparaci├│n a la fabricaci├│n de nuevos modelos, y crearon un jerg├│n sin muelles compuesto por una tela met├ílica insertada en un bastidor, que llamaron somier "Numancia". Fue el detonante de un crecimiento notable, que incluy├│ el establecimiento de f├íbricas fuera de Zaragoza. Tras la guerra 1936-1939, Andr├®s Luc├¡a dej├│ la direcci├│n de la f├íbrica de Madrid a Antonio Beter├®, que en 1949 constituy├│ la compa├▒├¡a F├íbricas Luc├¡a Antonio Beter├®, S.A." (FLABESA). Una d├®cada m├ís tarde, fue redenominada "Flex". En la imagen, publicidad de la f├íbrica de la calle Las Mercedes, luego calle Almagro. Fuente visual: "Arag├│n : revista gr├ífica de cultura aragonesa" (A├▒o II, N┬║ 9, junio 1926). Fuente textual: www.mcnbiografias.com/app-bio/do/show?key=betere-salvador...', 1926, 1926, 1926, 'Anos 20', 'CENTRO', 41.64836800, -0.88795800, '0101000020E6100000161747E5266AECBFEFE2FDB8FDD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15658340065.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15658340065.webp', 'https://www.flickr.com/photos/zaragozaantigua/15658340065/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21555, 'Puerta del Carmen 1927', 'Foto: A. de la Barrera. "Aislamiento de la Puerta del Carmen. Desfile de Artiller├¡a". Fuente: www.todocoleccion.net', 1927, 1927, 1927, 'Anos 20', 'CENTRO', 41.64982500, -0.88759100, '0101000020E61000007C2AA73D2567ECBFC58F31772DD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21381835558.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21381835558.webp', 'https://www.flickr.com/photos/zaragozaantigua/21381835558/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21600, 'Puerta del Carmen 1927', 'Institucional inauguraci├│n del "aislamiento" de la puerta del Carmen, que supuso el derribo de aquellas viviendas que, a la derecha de la imagen, recordaban que, durante siglos, fue una puerta de verdad. En esas viviendas estuvo, desde 1895, el original Caf├® Levante, que hubo de emigrar a otro sitio. Esta puerta, como escenario de sucesos sin par en la historia de la ciudad, fue despojada de su funcionalidad, y convertida en exento monumento, cada vez m├ís exento y descontextualizado de su entorno. En la imagen, el alcalde Miguel Allu├® Salvador en pleno "meeting". Tras ├®l, el resto de la corporaci├│n municipal. Al fondo, el convento de la Encarnaci├│n. Fuente visual: Foto: Alejandro de la Barrera www.todocoleccion.net/', 1927, 1927, 1927, 'Anos 20', 'CENTRO', 41.64985800, -0.88766100, '0101000020E6100000B4E89D0AB867ECBFA185048C2ED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/25803894956.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/25803894956.webp', 'https://www.flickr.com/photos/zaragozaantigua/25803894956/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21601, 'P.┬║ de Pamplona 1927', 'Imagen panor├ímica del entronque del paseo de Pamplona con la puerta del Carmen, capturada en altura por Alejandro de la Barrera durante el Institucional acto de inauguraci├│n del "aislamiento" de la puerta del Carmen, en 1927, que en la imagen queda a la izquierda, fuera de plano. Nutrida presencia de autoridades, invitados, y p├║blico en general, congregados al final del frondoso bulevar del paseo de Pamplona. Al fondo, taller y garaje de ├ügreda Autom├│vil en una replaceta que luego desapareci├│ con la prolongaci├│n de la calle de Canfranc, calle que entonces acababa en la achaflanada esquina del nuevo colegio de la "Ense├▒anza", cuyos andamiajes de obras aparecen en franca progresi├│n. Al fondo, los restos del antiguo convento de Santa Teresa de las Carmelitas Descalzas de San Jos├®, acondicionado como Gobierno Militar. Un retratista se afana en retratar a las fuerzas vivas militares, religiosas, e institucionales, encabezadas por el hiperactivo alcalde, y nunca bien ponderado, Miguel Allu├®. Fuente visual: Foto: Alejandro de la Barrera www.todocoleccion.net/', 1927, 1927, 1927, 'Anos 20', 'CENTRO', 41.64955700, -0.88745500, '0101000020E6100000677E35070866ECBFA6F10BAF24D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/25804414256.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/25804414256.webp', 'https://www.flickr.com/photos/zaragozaantigua/25804414256/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21662, 'Puerta del Carmen 1927', 'Fotograma de un reportaje dedicado a la inauguraci├│n oficial, el d├¡a 18 de mayo de ese a├▒o, del "total aislamiento" de la Puerta del Carmen que finalmente convirti├│ a esta reliquia en un monumento exento respecto a las edificaciones del entorno. Una multitud de paisanos abarrotaron la confluencia entre la calle de la Soberan├¡a Nacional (en la imagen, tras la puerta), la avenida de Hern├ín Cort├®s y los paseos de Pamplona y de Mar├¡a Agust├¡n, mientras ten├¡a lugar una "fiesta patri├│tica" de car├ícter militar y religioso con numerosos representantes locales de las instituciones del r├®gimen dictatorial del general Primo de Rivera. El inefable alcalde Miguel Allu├® Salvador protagoniz├│ un mitin en el que denomin├│ de forma pionera "altar de la patria" a esta puerta y "santuario de patriotismo" a Zaragoza, c├│digos que volver├¡an a ser utilizados hasta la saciedad una d├®cada despu├®s, en el marco de otra dictadura.', 1927, 1927, 1927, 'Anos 20', 'CENTRO', 41.64986700, -0.88766000, '0101000020E61000009DF4BEF1B567ECBFF4DF83D72ED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/54722175090.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/54722175090.webp', 'https://www.flickr.com/photos/zaragozaantigua/54722175090/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21903, 'Puerta del Carmen 1931', 'Imagen centrada en la Puerta del Carmen y su aspecto tras las obras de aislamiento que desde 1927 la dejaron aislada de su entorno edilicio. A la izquierda, tapias de la huerta de la iglesia y convento de la Encarnaci├│n de las carmelitas descalzas y la arbolada calle de la Soberan├¡a Nacional, cuyo tramo final del lado de los impares queda tras la puerta, en cuya esquina con el paseo de Pamplona destaca el Caf├® Arag├│n, muy cerca de donde estuvo el Caf├® de Levante hasta 1926. A la derecha, irregular esquina del paseo donde destaca el taller y garaje de la empresa de autobuses ├ügreda Autom├│vil.', 1931, 1931, 1931, 'Anos 30', 'CENTRO', 41.64986700, -0.88766000, '0101000020E61000009DF4BEF1B567ECBFF4DF83D72ED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51617755764.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51617755764.webp', 'https://www.flickr.com/photos/zaragozaantigua/51617755764/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21909, 'Puerta del Carmen c.1934', 'Imagen capturada en el ├║ltimo tramo de la calle de la Soberan├¡a Nacional, a la altura del convento de la Encarnaci├│n (a la derecha, fuera de plano) y centrada en la Puerta del Carmen, con su aspecto tras las obras de aislamiento realizadas la d├®cada anterior. Tras ella y hacia el fondo se abre la avenida de Hern├ín Cort├®s. Un carro se encamina hacia el paseo de Pamplona mediante una llamativa maniobra si se mira desde un punto de vista actual. Entonces, no. El fot├│grafo titul├│ esta fotograf├¡a de forma muy apropiada "Only gate left to city" (la ├║nica puerta que queda en la ciudad).', 1934, 1934, 1934, 'Anos 30', 'CENTRO', 41.65010800, -0.88731700, '0101000020E610000025EA059FE664ECBF1A6F2BBD36D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51760200560.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51760200560.webp', 'https://www.flickr.com/photos/zaragozaantigua/51760200560/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21977, 'Puerta del Carmen 1944', 'Celebraciones militares fascistas del D├¡a de los Ca├¡dos, el 30 de octubre de 1944, ante la Puerta del Carmen. Al fondo, el Convento de las Carmelitas de la Encarnaci├│n, en la esquina del paseo de Mar├¡a Agust├¡n con la calle del General Sanjurjo (hoy avenida de C├®sar Augusto). Fuente: www.keecua.com/', 1944, 1944, 1944, 'Anos 40', 'CENTRO', 41.64985800, -0.88766100, '0101000020E6100000B4E89D0AB867ECBFA185048C2ED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24929016893.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24929016893.webp', 'https://www.flickr.com/photos/zaragozaantigua/24929016893/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22163, 'Puerta del Carmen 1954', 'Con motivo del Congreso Mariano Nacional celebrado en Zaragoza en octubre de 1954, se congregaron im├ígenes de la Virgen procedentes de todo el pa├¡s. En la imagen, la Virgen de la Peana de Borja, ante la Puerta del Carmen, convenientemente decorada. Detr├ís, fuera de nuestra vista, la ciudad consolidada duerme la plomiza paz religiosa supuesta e impuesta. Fuente: cesbor.blogspot.com.es/', 1954, 1954, 1954, 'Anos 50', 'CENTRO', 41.64988000, -0.88767300, '0101000020E6100000C5591135D167ECBF892991442FD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30814265013.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30814265013.webp', 'https://www.flickr.com/photos/zaragozaantigua/30814265013/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22231, 'Puerta del Carmen c.1954', 'Imagen centrada en la Puerta del Carmen rodeada de la barandilla met├ílica con que fue aislada en 1927. Al fondo, muro perimetral de la huerta del convento de la Encarnaci├│n, cuya iglesia se destaca entre el gran vano central de la puerta, y cuya fachada principal se abre por la calle del General Sanjurjo.', 1954, 1954, 1954, 'Anos 50', 'CENTRO', 41.64993900, -0.88768200, '0101000020E610000091EEE714E467ECBF8EB27E3331D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/49942622867.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/49942622867.webp', 'https://www.flickr.com/photos/zaragozaantigua/49942622867/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22304, 'Puerta del Carmen 1964', 'Fototeca Universidad de Sevilla. Antonio Palau. Agosto de 1964. "Puerta del Carmen". Se han dejado la puerta abierta, y podemos ver el aspecto de la calle del General Sanjurjo (antigua de la Soberan├¡a Nacional), antes del "lifting" que la convertir├¡a en V├¡a Imperial primero, C├®sar Augusto despu├®s. Con la cirug├¡a, se recortaron tambi├®n los edificios de la derecha, aunque los que les sustituyeron compensaron con creces esa "p├®rdida", creciendo en vertical como regados por concentrado de vitaminas. Cayeron tambi├®n los ├írboles, y sembraron sal para que luego no creciese nada verde (org├ínico). A la izquierda, tras los ca├▒izos de obra, la construcci├│n del nuevo Monasterio de la Encarnaci├│n (Madres Carmelitas). Fuente visual: fototeca.us.es/imagen.jsp?id=25836&tipo=v&elto=1&...', 1964, 1964, 1964, 'Anos 60', 'CENTRO', 41.64983000, -0.88759400, '0101000020E6100000C00644882B67ECBFD7FA22A12DD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15617866936.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15617866936.webp', 'https://www.flickr.com/photos/zaragozaantigua/15617866936/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22325, 'Calle de Hern├ín Cort├®s 1962', 'Un reportaje fotogr├ífico familiar, seg├║n d├│nde haya sido realizado, es algo m├ís que un reportaje fotogr├ífico familiar. Tal es el caso. La nena ha sido retratada en la todav├¡a bastante tranquila, a efectos de circulaci├│n rodada a motor de explosi├│n, calle de Hern├ín Cort├®s, que fuera en tiempos tranquilo camino al convento de los Capuchinos que, una vez desamortizado, fue militarizado. A├▒os despu├®s de esta imagen, la calle se convirti├│ en prolongaci├│n de la autopista de C├®sar Augusto, y los ni├▒os dejaron de corretear, y los ├írboles, fuera. En la imagen, al fondo a la derecha, vista parcial del espectacular colegio de las "Adoratrices Esclavas del Sant├¡simo y de la Caridad", en esa ubicaci├│n desde 1910, en el n┬║ 10 de la calle. En 1972, durante la no oficial "Operaci├│n conventos y colegios religiosos", las Adoratrices se mudaron a otros pagos de la periferia, el edificio fue vendido, pagado, y piqueteado, y una enorme urbanizaci├│n con bloques de nueve alturas surgi├│ en el solar resultante. La nena, bien maja.', 1962, 1962, 1962, 'Anos 60', 'CENTRO', 41.64917000, -0.88887300, '0101000020E61000005E8429CAA571ECBFACC5A70018D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/16371316546.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/16371316546.webp', 'https://www.flickr.com/photos/zaragozaantigua/16371316546/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22499, 'Calle del General Sanjurjo c.1964', 'Imagen centrada en la fachada principal del convento de la Encarnaci├│n de las carmelitas recayente a la calle del General Sanjurjo, al norte de la Puerta del Carmen. Este edificio fue dise├▒ado en formas ecl├®cticas por El├¡as Ballesp├¡n Larroyed a finales del siglo XIX, cuando esta era la calle de la Soberan├¡a Nacional, como dependencias anexas a la dieciochesca iglesia conventual de esta orden. Poco despu├®s de la captura de esta fotograf├¡a, este edificio ser├¡a derribado para dar paso a un nuevo complejo carmelita construido sobre la antigua zona de huerta chaflanera con el paseo de Mar├¡a Agust├¡n y la nueva V├¡a Imperial.', 1964, 1964, 1964, 'Anos 60', 'CENTRO', 41.65045200, -0.88713500, '0101000020E6100000FA6184F06863ECBF14CFD90242D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/49603730673.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/49603730673.webp', 'https://www.flickr.com/photos/zaragozaantigua/49603730673/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22914, 'P.┬║ de M┬¬ Agust├¡n 1985', 'Movilizaci├│n contra Reagan y la OTAN convocada por la Asamblea Ciudadana el 5 de mayo de ese a├▒o ante la visita a Espa├▒a del presidente de Estados Unidos para garantizar el futuro de sus bases militares, y pedir colaboraci├│n en su cruzada contra la Nicaragua sandinista. La vista, que ha sido capturada desde la altura del n┬║ 16 del paseo de Pamplona, muestra a los participantes formando la consigna OTAN no y el s├¡mbolo de la paz en el tramo del paseo de Mar├¡a Agust├¡n hasta el Colegio P├║blico Joaqu├¡n Costa. Fuente: Agencia EFE.', 1985, 1985, 1985, 'Anos 80', 'CENTRO', 41.65020900, -0.88824200, '0101000020E610000050E09D7C7A6CECBF4D486B0C3AD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24599112706.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24599112706.webp', 'https://www.flickr.com/photos/zaragozaantigua/24599112706/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22957, 'Puerta del Carmen 1983', 'Imagen capturada desde el punto de vista de un peat├│n situado temerariamente al principio de la calle de Hern├ín Cort├®s, y centrada en la "hist├│rica" (sic) Puerta del Carmen con el fondo de la avenida de C├®sar Augusto. Esta era la dieciochesca versi├│n de la hist├│rica puerta que desde antiguo aqu├¡ abr├¡a/cerraba el ingreso a la ciudad por el camino de Madrid que pasaba por Daroca. A la izquierda, el moderno convento de la Encarnaci├│n, en un entorno descontextualizado desde la d├®cada de los a├▒os 60 del pasado siglo XX, especialmente desde la construcci├│n del rascacielos de la derecha, que marc├│ tendencia a los nuevos inmuebles construidos desde entonces en la V├¡a Imperial. Tras ├®l, solar esquinero con la calle de Jos├® Luis Albareda que ser├¡a construido pocos a├▒os despu├®s de esta fotograf├¡a. Al fondo, visible a trav├®s del vano central de la puerta, el "Edificio Residencial-Comercial Salamero", sito junto a la hom├│nima plaza, antigua de la Santa Fe.', 1983, 1983, 1983, 'Anos 80', 'CENTRO', 41.64985900, -0.88762800, '0101000020E6100000C571E0D57267ECBF710168942ED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/49340625047.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/49340625047.webp', 'https://www.flickr.com/photos/zaragozaantigua/49340625047/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22981, 'Puerta del Carmen 1997', 'Rehabilitaci├│n de la Puerta del Carmen de Zaragoza, tras el golpe recibido al chocar un autob├║s contra ella. La toma, nocturna, evoca monstruos, oscurantismo, torturas rituales. Fuente visual: www.zaragoza.es/ciudad/actividades/ficha_Agenda?codigo=13...', 1997, 1997, 1997, 'Anos 90', 'CENTRO', 41.64982500, -0.88759100, '0101000020E61000007C2AA73D2567ECBFC58F31772DD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15913810051.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15913810051.webp', 'https://www.flickr.com/photos/zaragozaantigua/15913810051/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22988, 'Puerta del Carmen 1997', 'Imagen del estado de la Puerta del Carmen de Zaragoza tras sufrir el choque de un autocar, el 23 de febrero de 1997. Se observa, adem├ís de la ca├¡da de la bola de piedra, el desplazamiento del lateral. Fuente: Foto ├üngel de Castro, en www.elperiodicodearagon.com/', 1997, 1997, 1997, 'Anos 90', 'CENTRO', 41.64982500, -0.88759100, '0101000020E61000007C2AA73D2567ECBFC58F31772DD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19860137941.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19860137941.webp', 'https://www.flickr.com/photos/zaragozaantigua/19860137941/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23014, 'Puerta del Carmen 1997', 'Imagen de la puerta del Carmen embalada y tapiada durante el proceso de reparaci├│n a la que se vio sometida tras ser impactada por un autob├║s urbano. La isleta donde est├í enclavada fue, adem├ís, reforzada con pivotes en las zonas laterales, las m├ís expuestas a potenciales nuevos impactos directos del tr├ífico rodado que la asedia. Al fondo, la avenida de C├®sar Augusto. Fuente visual: revista "Arag├│n tur├¡stico y monumental", SIPA.', 1997, 1997, 1997, 'Anos 90', 'CENTRO', 41.64985600, -0.88767300, '0101000020E6100000C5591135D167ECBF008E3D7B2ED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/34911631795.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/34911631795.webp', 'https://www.flickr.com/photos/zaragozaantigua/34911631795/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23273, 'Bater├¡a de la Puerta del Carmen 1808', '"Bater├¡a de la Puerta del Carmen". Serie Ruinas de Zaragoza, de Juan G├ílvez (dibujo) y Fernando Brambila (grabado), C├ídiz, 1812. Fuente visual: bvpb.mcu.es/', 1808, 1808, 1808, 'Siglo XIX', 'CENTRO', 41.65019300, -0.88779100, '0101000020E610000040DCD5ABC868ECBF488B338639D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/18931581573.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/18931581573.webp', 'https://www.flickr.com/photos/zaragozaantigua/18931581573/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23968, 'P.┬║ de Pamplona 1974', 'Archivo Municipal Zaragoza. Jos├® Jaria Serrano. 23/05/1974. "Carroza de las majas de Alemania y Yugoslavia." Desfile con motivo de las "Fiestas de Primavera-Coso Blanco". La carroza es un jeep de los EEUU de norteam├®rica. La maja alemana es de la Rep├║blica Federal de Alemania, y la maja yugoslava, de la Rep├║blica Federal Socialista de Yugoslavia. El conductor, ind├¡gena del Reino de Espa├▒a. La caravana transcurre por el P┬║ de Pamplona. Al fondo, tras la peineta gigante, uno de los gigantes levantados al albur del ensanchamiento de C├®sar Augusto. A su derecha, el edificio Canfranc-P┬║ Pamplona, supervive. Su vecino a la derecha, no.', 1974, 1974, 1974, 'Anos 70', 'CENTRO', 41.64912200, -0.88721000, '0101000020E6100000A4E4D5390664ECBF9B8E006E16D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15093537330.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15093537330.webp', 'https://www.flickr.com/photos/zaragozaantigua/15093537330/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24003, 'P.┬║ de Pamplona 1974', '"Carroza de las majas de Finlandia y Paraguay." Celebraci├│n en mayo con motivo de las "Fiestas de Primavera-Coso Blanco". La carroza es un jeep que transita por el paseo de Pamplona, y esta imagen permite una amplia visual, al fondo, y a la derecha, del antiguo edificio del paseo con los n├║meros 12-14, que unos pocos a├▒os despu├®s ser├¡a derribado y sustituido por lo que ahora hay. Fuente visual: Jos├® Jaria Serrano (Archivo P├║blico Municipal)', 1974, 1974, 1974, 'Anos 70', 'CENTRO', 41.64922800, -0.88710100, '0101000020E6100000F5F6E7A22163ECBFE1D231E719D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22479738907.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22479738907.webp', 'https://www.flickr.com/photos/zaragozaantigua/22479738907/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24104, 'P┬║. de Pamplona 1972', 'Imagen capturada en el paseo de Pamplona durante las Fiestas de Primavera y dentro del evento denominado "Concurso de la Maja Internacional", donde veinticinco "bellas se├▒oritas" representantes de sus respectivos pa├¡ses se disputaron ese t├¡tulo en Zaragoza. La luminosa y colorista fotograf├¡a fue realizada durante el "Coso Blanco" celebrado en este paseo, consistente en un desfile de "carrozas" o "jeeps con peineta", donde las pretendientes al galard├│n y por parejas, ataviadas con sus respectivos trajes folkl├│ricos t├¡picos, lanzaban serpentinas y confetti a los miles de asistentes que observaban su paso. En primer t├®rmino, la "carroza" con la representante de USA y su "traje regional" que, a falta de otras referencias hist├│ricas, parece consistir en un remedo femenino del traje del simb├│lico "T├¡o Sam"; a su lado, menos espectacular, la representante de la monarqu├¡a federal parlamentaria de B├®lgica. Al fondo y a la izquierda, una vista del grupo de "Majorettes" de Zaragoza que amenizaban el desfile adem├ís de bandas de m├║sica y fanfarrias, y lanzamiento de cohetes. Tras ellas, el nuevo convento de las Encarnaci├│n, y el moderno entorno de la Puerta del Carmen donde destaca el enorme Edificio Ebrosa y el rascacielos que se├▒ala el arranque de la calle del General Sanjurjo, un tramo de la cual tambi├®n fue escenario del paso de este "Coso Blanco" coincidiendo con la celebraci├│n del solemne d├¡a de la Ascensi├│n, uno de esos tres d├¡as que la tradici├│n cristiana dice que "brillan m├ís que el sol".', 1972, 1972, 1972, 'Anos 70', 'CENTRO', 41.64920200, -0.88723100, '0101000020E610000081EA1F443264ECBFB83F170D19D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51505927636.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51505927636.webp', 'https://www.flickr.com/photos/zaragozaantigua/51505927636/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24526, 'P.┬║ de Pamplona 1982', 'Imagen centrada en la fachada del antiguo n┬║ 7 del paseo de Pamplona, dise├▒ado por el arquitecto Julio Bravo en 1901 para Ram├│n Hern├índez donde se ingresaba a los antiguos lavaderos de Pignatelli desde el paseo de la Lealtad. De tres plantas m├ís los bajos, esta casa era una muestra de las ecl├®cticas formas usadas en el tr├ínsito del siglo XIX al XX. En el momento de capturar la imagen, los bajos comerciales estaban ocupados por una tienda de muebles de Sim├│n Loscertales Bona, que ser├¡a la ├║ltima en activo en la ciudad. A principios del siglo XXI este edificio fue objeto de una intensa remodelaci├│n que le a├▒adi├│ cuatro plantas en altura de traza postmoderna. A la izquierda, el antiguo n┬║ 5 del paseo, que originalmente tambi├®n fue dise├▒ado por Julio Bravo, y que tambi├®n fue objeto de una profunda transformaci├│n tanto en altura como en formas. A la derecha, el modern├¡simo y reciente n┬║ 9, de diez alturas. Fuente visual: AMZ', 1982, 1982, 1982, 'Anos 80', 'CENTRO', 41.64845800, -0.88694000, '0101000020E6100000A774B0FECF61ECBF2F6AF7AB00D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/42261475914.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/42261475914.webp', 'https://www.flickr.com/photos/zaragozaantigua/42261475914/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24962, 'Velocipedistas Zaragoza 1882', 'Revista "Arag├│n", SIPA, n┬║ 25, octubre 1927. 1882. Los anales se remontan a los a├▒os 70 (del XIX) para atestiguar la epifan├¡a del ciclismo zaragozano. El lugar: Teatro "Prado Aragon├®s", donde San Miguel con Isaac Peral. J├│venes de la "buena" sociedad de entonces maniobraban en veloc├¡pedos de madera herederos de la "draisiana" o "m├íquina andante" de comienzos del siglo. Un poco despu├®s la t├®cnica introdujo el metal y los pedales, y una rueda delantera que alcanzaba el metro y medio de altura (la trasera s├│lo llegaba a los 40 ctm.) Estos nuevos artefactos, y los locos montados en ellos, pronto causaron sensaci├│n (positiva) con su rodaje por las calles de la ciudad, conquistando pros├®litos y militantes hasta el punto que, un poco m├ís tarde, a├▒o de 1882, se constituy├│ la primera entidad ciclista local, denominada "Sociedad de Velocipedistas", con domicilio social en el Paseo de Pamplona. La imagen capta un posado de algunos de esos pioneros de las dos ruedas, sin v├®rtigo, junto con sus locos cacharros, a la puerta de su sede social: Gamborenea, Marco, Baraza, Boayed, Cibri, Lostz, y Sra.', 1882, 1882, 1882, 'Siglo XIX', 'CENTRO', 41.64937800, -0.88734400, '0101000020E61000008BA8893E1F65ECBFF65E7CD11ED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14850347741.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14850347741.webp', 'https://www.flickr.com/photos/zaragozaantigua/14850347741/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24967, 'Epi 1974', 'Juan Antonio San Epifanio naci├│ en la calle Dami├ín Forment en 1959. En 1968 su familia se mud├│ a la calle Jos├® Pellicer (Barrio de San Jos├®), donde vivi├│ hasta los 15 a├▒os. Comenz├│ la pr├íctica del baloncesto en la Instituci├│n Sindical Virgen del Pilar (Paseo Reyes de Arag├│n), junto al Canal Imperial y enfrente del Stadium Casablanca. Aunque "era muy malo" (seg├║n ├®l mismo), era muy alto, y eso en baloncesto es un valor seguro. Lo de ser alto le serv├¡a, adem├ís, para saltar mejor la valla del cercano colegio de los PP. Agustinos, donde practicaba con las canastas del patio. En 1971 entr├│ en el C. N. Helios, hasta llegar a la categor├¡a juvenil. Con quince a├▒os de edad, fue fichado por el F.C. Barcelona por mediaci├│n de su hermano mayor. All├¡ estar├¡a hasta 1995, firmando una trayectoria deportiva m├ís que impresionante. En la imagen, Juan Antonio San Epifanio, "Epi", cuando era juvenil en el Helios, posando ante la Puerta del Carmen.', 1974, 1974, 1974, 'Anos 70', 'CENTRO', 41.64977300, -0.88758800, '0101000020E6100000384E0AF31E67ECBF7369FCC22BD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15256350857.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15256350857.webp', 'https://www.flickr.com/photos/zaragozaantigua/15256350857/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25072, 'Alfonso XIII, 1908', '"Francia y Espa├▒a. Monsieur Cruppi, ministro de Comercio, y Revoil, embajador de Francia, saludan a Su Majestad Alfonso XIII en Zaragoza". Ilustraci├│n, 1908. Los personajes est├ín situados extramuros de la ciudad, con la Puerta del Carmen a sus espaldas. Fuente: Le Petit Journal, 1908.', 1908, 1908, 1908, 'Anos 1900', 'CENTRO', 41.64961200, -0.88779200, '0101000020E610000057D0B4C4CA68ECBF698B6B7C26D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/18342645394.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/18342645394.webp', 'https://www.flickr.com/photos/zaragozaantigua/18342645394/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25463, 'Puerta del Carmen 1883', 'A.M.Z. Sign. 0884. Puerta del Carmen bombardeada por los franceses en los dos c├®lebres sitios de 1808 y 1809 (de fotograf├¡a de Laurent). 1883. La puerta de Baltax o del Carmen (1782) cerraba la ciudad al suroeste. Actualmente se conserva en pie, al final de la avenida C├®sar Augusto.', 1883, 1883, 1883, 'Siglo XIX', 'CENTRO', 41.64984000, -0.88762200, '0101000020E61000003DB9A6406667ECBFFAD005F52DD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14835922566.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14835922566.webp', 'https://www.flickr.com/photos/zaragozaantigua/14835922566/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25464, 'Puerta del Carmen 1877', 'Archivo RUIZ VERNACCI, Jean Laurent y C├¡a. 1872-1879. "Puerta de Nuestra Sra. del Carmen, memorable por la defensa que hizo de ella la hero├¡na de Zaragoza durante el famoso sitio de 1808."', 1877, 1877, 1877, 'Siglo XIX', 'CENTRO', 41.64986700, -0.88754800, '0101000020E6100000AA2A3410CB66ECBFF4DF83D72ED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14865951902.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14865951902.webp', 'https://www.flickr.com/photos/zaragozaantigua/14865951902/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25465, 'Puerta del Carmen 1954', 'Archivo Municipal de Zaragoza. Archivo Arribas. 1954. "Puerta del Carmen".', 1954, 1954, 1954, 'Anos 50', 'CENTRO', 41.64987500, -0.88763900, '0101000020E6100000BFEE74E78967ECBF77BE9F1A2FD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14880296789.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14880296789.webp', 'https://www.flickr.com/photos/zaragozaantigua/14880296789/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25466, 'Puerta del Carmen 1951', 'Archivo Municipal de Zaragoza. Archivo Arribas. 1950. "[Puerta del Carmen y Paseo Mar├¡a Agust├¡n]". "La Puerta del Carmen est├í situada en la confluencia del Paseo de Pamplona con el inicio de la V├¡a Imperial, se denomin├│ Puerta de Baltax antes de llamarle del Carmen. A los pocos a├▒os de construirse padeci├│ los efectos destructores de los Sitios, posteriormente en 1838, durante la primera Guerra Carlista, el ej├®rcito de Caba├▒ero asalt├│ por dicha entrada la ciudad. Se trata de una sencilla puerta de piedra, cuya estructura a modo de arco triunfal romano evoca conocidos ejemplos neocl├ísicos madrile├▒os. Compuesta de un cuerpo central m├ís alto y dos cuerpos laterales, cada uno de ellos presenta un vano rectangular. El central sirvi├│ para el tr├ínsito de animales y veh├¡culos y los laterales s├│lo para viandantes. Su ornamentaci├│n es escasa, se reduce a la piedra clasicista y a su remate con decoraci├│n de bolas."', 1951, 1951, 1951, 'Anos 50', 'CENTRO', 41.64982500, -0.88759100, '0101000020E61000007C2AA73D2567ECBFC58F31772DD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15044018576.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15044018576.webp', 'https://www.flickr.com/photos/zaragozaantigua/15044018576/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25469, 'Puerta del Carmen 1889', '"Saragosse. Porte del Carmen". J. L├®vy et Cie, 1889. Agence Roger-Viollet, Par├¡s. Fuente: Zaragoza en la mirada ajena. Cortes de Arag├│n, 2012', 1889, 1889, 1889, 'Siglo XIX', 'CENTRO', 41.64982500, -0.88759100, '0101000020E61000007C2AA73D2567ECBFC58F31772DD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/16806009622.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/16806009622.webp', 'https://www.flickr.com/photos/zaragozaantigua/16806009622/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25470, 'P.┬║ de Pamplona 1962', 'Imagen de la "trasformaci├│n de la estructura" del antiguo paseo de Pamplona, que en plata significaba convertirlo en lo que el paseo de la Independencia era ya desde el a├▒o anterior: una despejada pista para el tr├ínsito del tr├ífico rodado a motor de explosi├│n. Esta actuaci├│n era calificada de "mejora", y supon├¡a eliminar los males del and├®n central peatonal, y todo lo que en ├®l hubiera, o hubiese. Unos a├▒os antes ya hab├¡a sido desmontado el "Monumento a la Exposici├│n Hispano-Francesa de 1908", y trasladado donde no molestara. En la imagen, estado de la cuesti├│n con remoci├│n de ├írboles entre bancos de sentarse y montoneras de tierra. Al fondo, la puerta del Carmen, y m├ís al fondo, a la derecha, aprovechando lo despejado del entorno, despunta la torrecilla oriental de la Casa-Noviciado de las Hermanas de la Caridad de Santa Ana, en la calle Madre Rafols. Fuente visual: Gerardo Sancho Ramo, Archivo P├║blico Municipal.', 1962, 1962, 1962, 'Anos 60', 'CENTRO', 41.64982500, -0.88759100, '0101000020E61000007C2AA73D2567ECBFC58F31772DD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22516579533.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22516579533.webp', 'https://www.flickr.com/photos/zaragozaantigua/22516579533/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25471, 'Puerta del Carmen 1955', 'Nocturna imagen de la Puerta del Carmen iluminada, todav├¡a con su per├¡metro cercado y ajardinado, cuando a├║n no era una rotonda para autom├│viles. Al fondo, la calle General Sanjurjo, con m├ís oscuros, que claros. Fuente visual: www.delcampe.net/', 1955, 1955, 1955, 'Anos 50', 'CENTRO', 41.64982500, -0.88759100, '0101000020E61000007C2AA73D2567ECBFC58F31772DD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22575360344.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22575360344.webp', 'https://www.flickr.com/photos/zaragozaantigua/22575360344/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
